insert into public.recipes (id, doc, status) values ('turkey_black_bean_chili', '{"id":"turkey_black_bean_chili","name":"Turkey & black bean chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":500},{"f":"black_beans","q":400},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"chili_powder","q":8},{"f":"cumin","q":5},{"f":"broth","q":400},{"f":"olive_oil","q":15}],"steps":["Warm the oil in a heavy pot over medium-high. Brown the turkey, breaking it up, about 5 minutes.","Add the diced onion and bell pepper; cook until soft, 4 minutes. Stir in the minced garlic, chili powder and cumin for 30 seconds until fragrant.","Pour in the crushed tomatoes, broth and drained beans. Bring to a simmer.","Drop the heat to low and simmer uncovered 25 minutes, stirring now and then, until thick.","Taste, season, and serve — it is even better the next day."],"tip":"Freezes beautifully in single portions for no-effort future dinners."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cobb_chicken_salad', '{"id":"cobb_chicken_salad","name":"Chopped chicken Cobb salad","emoji":"🥗","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"romaine","q":1},{"f":"eggs","q":2},{"f":"avocado","q":1},{"f":"cherry_tomatoes","q":140},{"f":"cheddar","q":40},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5}],"steps":["Hard-boil the eggs (10 minutes), cool in cold water, peel and quarter.","Season the chicken and sear in a skillet over medium-high, 5–6 minutes per side, until cooked through. Rest, then slice.","Chop the romaine and arrange in wide bowls. Halve the tomatoes, dice the avocado.","Row up the chicken, eggs, avocado, tomatoes and cheddar over the lettuce.","Whisk the olive oil with the lemon’s juice, a pinch of salt and pepper; dress just before eating."],"tip":"Everything but the avocado and dressing can be prepped a day ahead."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_oat_pancakes', '{"id":"banana_oat_pancakes","name":"Banana oat pancakes","emoji":"🥞","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"banana","q":2},{"f":"oats","q":120},{"f":"eggs","q":2},{"f":"milk","q":120},{"f":"cinnamon","q":2},{"f":"butter","q":10},{"f":"honey","q":20}],"steps":["Blitz the oats in a blender until floury. Add the bananas, eggs, milk and cinnamon; blend until smooth. Rest 5 minutes to thicken.","Heat a nonstick skillet over medium and slick with a little butter.","Pour quarter-cup rounds and cook until bubbles pop on top, about 2 minutes.","Flip and cook 1–2 minutes more until golden.","Stack and finish with the honey."],"tip":"Spottier bananas mean sweeter pancakes — this is what those two sad ones are for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_fried_rice', '{"id":"chicken_fried_rice","name":"Better-than-takeout chicken fried rice","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free"],"allergens":["eggs","soy","gluten"],"time":25,"servings":2,"ing":[{"f":"rice","q":180},{"f":"chicken_thigh","q":250},{"f":"eggs","q":2},{"f":"peas_frozen","q":100},{"f":"carrots","q":80},{"f":"scallions","q":0.5},{"f":"soy_sauce","q":30},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20}],"steps":["Cook the rice ahead if you can — cold, dry rice fries best.","Stir-fry the diced chicken in half the oil over high heat until golden, 4–5 minutes; set aside.","Scramble the eggs in the pan, then add the remaining oil with the diced carrot, peas, ginger and garlic; fry 2 minutes.","Add the rice, pressing it into the hot pan; let it crackle 1 minute before tossing.","Return the chicken, splash in the soy sauce, toss with sliced scallions and serve."],"tip":"High heat and a crowded-pan intolerance are the two rules of fried rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_tofu_stirfry', '{"id":"ginger_tofu_stirfry","name":"Crispy ginger-garlic tofu stir-fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten"],"time":30,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"broccoli","q":450},{"f":"bell_pepper","q":1},{"f":"soy_sauce","q":30},{"f":"ginger","q":12},{"f":"garlic","q":0.3},{"f":"rice","q":160},{"f":"scallions","q":0.5},{"f":"olive_oil","q":20}],"steps":["Press the tofu 10 minutes between towels, then cube it. Start the rice.","Sear the tofu in half the oil over medium-high, undisturbed 3 minutes a side, until deeply golden. Set aside.","Stir-fry the broccoli florets and sliced pepper in the rest of the oil, 4 minutes, until crisp-tender.","Add the grated ginger and minced garlic for 30 seconds, then return the tofu with the soy sauce and toss to glaze.","Serve over the rice, showered with sliced scallions."],"tip":"A dry pan-side and patience make tofu crispy — poking it early makes it stick."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_garlic_salmon_bowl', '{"id":"honey_garlic_salmon_bowl","name":"Honey-garlic salmon rice bowl","emoji":"🍣","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten"],"time":25,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"honey","q":30},{"f":"soy_sauce","q":30},{"f":"garlic","q":0.3},{"f":"rice","q":160},{"f":"broccoli","q":450},{"f":"scallions","q":0.5}],"steps":["Start the rice; steam the broccoli florets over it for the final 5 minutes.","Stir the honey, soy sauce and minced garlic into a glaze.","Sear the salmon skin-side down in a hot skillet, 4 minutes, then flip for 2.","Pour the glaze around the fish and let it bubble and thicken 1–2 minutes, spooning it over.","Build bowls: rice, broccoli, salmon, extra glaze, sliced scallions."],"tip":"Pull the salmon while its center is still deep pink — it finishes in the glaze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chana_masala', '{"id":"chana_masala","name":"Chana masala","emoji":"🍛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"crushed_tomatoes","q":300},{"f":"curry_powder","q":10},{"f":"cumin","q":4},{"f":"cilantro","q":0.3},{"f":"rice","q":160},{"f":"olive_oil","q":15}],"steps":["Start the rice. Soften the diced onion in the oil over medium heat, 6–8 minutes, until golden at the edges.","Add the minced garlic, grated ginger, curry powder and cumin; fry 1 minute until the pan smells incredible.","Pour in the crushed tomatoes and simmer 5 minutes until slightly darkened.","Add the drained chickpeas with a splash of water; simmer 10 minutes, mashing a few against the pot to thicken the sauce.","Season, shower with chopped cilantro, and serve over the rice."],"tip":"The long onion sauté is the flavor foundation — don’t rush those first minutes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_chicken_curry', '{"id":"coconut_chicken_curry","name":"Coconut chicken curry","emoji":"🥥","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"coconut_milk","q":200},{"f":"curry_powder","q":12},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"tomato","q":2},{"f":"rice","q":160},{"f":"olive_oil","q":15}],"steps":["Start the rice. Brown the chicken pieces in the oil over medium-high, about 4 minutes; set aside.","Soften the diced onion in the same pot, 5 minutes, then add garlic, ginger and curry powder for 1 minute.","Add the chopped tomatoes and cook until they slump, 3 minutes.","Return the chicken, pour in the coconut milk, and simmer gently 15 minutes until the sauce coats a spoon.","Season and serve over rice."],"tip":"Thighs stay juicy through the simmer — this is exactly what they are for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_dal', '{"id":"spinach_dal","name":"Spinach dal","emoji":"🥬","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"spinach","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"cumin","q":5},{"f":"curry_powder","q":8},{"f":"rice","q":120},{"f":"olive_oil","q":15}],"steps":["Rinse the lentils and simmer in 3 cups of water until tender, 20–25 minutes, skimming any foam.","Meanwhile cook the rice, and fry the diced onion in the oil until deeply golden, 8 minutes.","Add the garlic, ginger, cumin and curry powder to the onions for 1 minute.","Fold the spiced onions into the lentils, add the spinach, and simmer 3 minutes until wilted and thick.","Season generously and serve with the rice."],"tip":"The fried-onion finish (tadka) is the difference between fine dal and great dal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('marinara_spaghetti', '{"id":"marinara_spaghetti","name":"Garlic-basil marinara spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"spaghetti","q":200},{"f":"crushed_tomatoes","q":400},{"f":"garlic","q":0.4},{"f":"onion","q":0.5},{"f":"basil","q":0.3},{"f":"olive_oil","q":25},{"f":"parmesan","q":30}],"steps":["Sizzle the sliced garlic and diced onion in the olive oil over medium-low until soft and fragrant, 5 minutes — no color.","Add the crushed tomatoes with a pinch of salt; simmer 15 minutes until glossy.","Cook the spaghetti in well-salted water to just shy of al dente; reserve a cup of pasta water.","Drag the pasta into the sauce with a splash of its water and toss over heat 1 minute until the sauce clings.","Tear in the basil, twirl into bowls, and finish with grated parmesan."],"tip":"Finishing the pasta *in* the sauce is the entire trick of Italian pasta."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_pomodoro_mozzarella', '{"id":"chicken_pomodoro_mozzarella","name":"Skillet chicken pomodoro with mozzarella","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"crushed_tomatoes","q":300},{"f":"garlic","q":0.3},{"f":"mozzarella","q":100},{"f":"basil","q":0.3},{"f":"spaghetti","q":160},{"f":"olive_oil","q":15}],"steps":["Halve the chicken breasts horizontally into cutlets, season, and sear in the oil 3 minutes per side; set aside.","Fry the sliced garlic in the same skillet 30 seconds, then add the crushed tomatoes and simmer 8 minutes.","Meanwhile cook the spaghetti in salted water.","Nestle the chicken back into the sauce, top each cutlet with mozzarella, cover 3 minutes until melted.","Serve over the spaghetti with torn basil."],"tip":"Thin cutlets cook fast and stay tender — thick breasts do neither."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_parmesan_frittata', '{"id":"zucchini_parmesan_frittata","name":"Zucchini-parmesan frittata","emoji":"🍳","cuisine":"Italian","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"zucchini","q":1},{"f":"parmesan","q":40},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Sauté the thinly sliced zucchini and onion in the oil in an ovenproof skillet until soft and lightly golden, 6 minutes.","Whisk the eggs with most of the parmesan, the salt and pepper.","Pour the eggs over the vegetables on medium-low; cook undisturbed until the edges set, 4 minutes.","Scatter the remaining parmesan on top and finish under the broiler 2–3 minutes until puffed and golden.","Rest 2 minutes, slice into wedges, eat warm or room-temperature."],"tip":"A frittata is dinner insurance — any vegetable in the crisper works."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_chopped_pita_plate', '{"id":"greek_chopped_pita_plate","name":"Greek chopped salad pita plate","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"feta","q":80},{"f":"onion","q":0.3},{"f":"oregano","q":2},{"f":"olive_oil","q":20},{"f":"pita","q":2},{"f":"hummus","q":120},{"f":"romaine","q":0.5}],"steps":["Chop the cucumber, tomatoes and romaine; slice the onion paper-thin.","Toss the vegetables with the olive oil, oregano and a pinch of salt.","Warm the pitas in a dry skillet 30 seconds per side.","Swoosh the hummus across two plates, pile the salad over, and crumble the feta on top.","Serve with the warm pitas for scooping."],"tip":"Salting the tomatoes five minutes early deepens the whole salad."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_oregano_salmon', '{"id":"lemon_oregano_salmon","name":"Lemon-oregano salmon over garlicky spinach","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":["fish"],"time":20,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"lemon","q":1},{"f":"olive_oil","q":20},{"f":"oregano","q":3},{"f":"spinach","q":200},{"f":"garlic","q":0.2}],"steps":["Rub the salmon with half the oil, the oregano, salt and the zest of the lemon.","Sear skin-side down in a hot skillet 4 minutes; flip for 2 more, then rest on a plate.","In the same pan, sizzle the sliced garlic in the remaining oil for 30 seconds.","Pile in the spinach and toss just until collapsed, 1 minute.","Plate the spinach under the salmon and finish everything with the lemon’s juice."],"tip":"Zest before you juice — it is impossible the other way around."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_quinoa_bowl', '{"id":"mediterranean_quinoa_bowl","name":"Mediterranean chickpea-quinoa bowl","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","sesame"],"time":25,"servings":2,"ing":[{"f":"quinoa","q":150},{"f":"chickpeas","q":250},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":140},{"f":"feta","q":60},{"f":"lemon","q":1},{"f":"olive_oil","q":20},{"f":"hummus","q":80}],"steps":["Rinse the quinoa and simmer in double its volume of salted water until the germ spirals out, 15 minutes. Fluff.","Crisp the drained chickpeas in a dry skillet with a pinch of salt, 5 minutes.","Dice the cucumber, halve the tomatoes, and whisk the lemon juice with the olive oil.","Build bowls: quinoa, chickpeas, vegetables, a swoosh of hummus.","Crumble the feta over and dress with the lemon oil."],"tip":"Toasting cooked chickpeas gives bean-haters something to reconsider."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salsa_chicken_tacos', '{"id":"salsa_chicken_tacos","name":"Weeknight salsa-braised chicken tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"salsa","q":200},{"f":"onion","q":0.5},{"f":"tortillas","q":6},{"f":"avocado","q":1},{"f":"cilantro","q":0.3},{"f":"lime","q":1}],"steps":["Sear the chicken thighs in a hot skillet 3 minutes per side.","Pour the salsa over with a splash of water, cover, and simmer 12 minutes until the chicken shreds easily.","Shred the chicken into the sauce and let it soak up the pan juices.","Char the tortillas directly over the flame or in a dry skillet, seconds per side.","Fill with chicken, sliced avocado, diced raw onion, cilantro, and a squeeze of lime."],"tip":"A good jarred salsa is a legitimate braising liquid — this is the shortcut that tastes like it wasn’t."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_burrito_bowls', '{"id":"black_bean_burrito_bowls","name":"Black bean burrito bowls","emoji":"🥣","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"rice","q":160},{"f":"black_beans","q":400},{"f":"corn_frozen","q":120},{"f":"salsa","q":150},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"cheddar","q":50},{"f":"sour_cream","q":60}],"steps":["Cook the rice, then fold in the lime zest and half its juice.","Warm the beans with a splash of water and a pinch of cumin or salt; char the corn in a dry skillet 3 minutes.","Halve and slice the avocado.","Build bowls: lime rice, beans, corn, salsa.","Top with cheddar, a spoon of sour cream, cilantro, avocado, and the rest of the lime."],"tip":"Charring frozen corn straight from the bag is a free flavor upgrade."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_taco_lettuce_wraps', '{"id":"turkey_taco_lettuce_wraps","name":"Turkey taco lettuce wraps","emoji":"🥬","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"romaine","q":1},{"f":"chili_powder","q":6},{"f":"cumin","q":4},{"f":"onion","q":0.5},{"f":"tomato","q":2},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Brown the turkey in the oil over medium-high, breaking it up, 5 minutes.","Add the diced onion, chili powder and cumin; cook 3 minutes more, then splash in water to make it saucy.","Separate the romaine into cup-shaped leaves; dice the tomato and avocado.","Spoon the spiced turkey into the leaves.","Top with tomato and avocado and finish with lime."],"tip":"Double the filling and tomorrow’s lunch is a taco salad."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('curried_tofu_scramble', '{"id":"curried_tofu_scramble","name":"Curried tofu scramble","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":["soy"],"time":15,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"onion","q":0.5},{"f":"bell_pepper","q":1},{"f":"spinach","q":80},{"f":"curry_powder","q":4},{"f":"olive_oil","q":15},{"f":"salt","q":2}],"steps":["Warm the oil in a skillet over medium and soften the diced onion and pepper, 4 minutes.","Crumble in the tofu with your hands — ragged pieces catch the seasoning best.","Sprinkle over the curry powder and salt; fry 4–5 minutes until the tofu dries out a little and takes color.","Fold in the spinach until just wilted.","Taste, season harder than you think, and serve hot."],"tip":"Firm tofu, well crumbled, has scrambled-egg texture without trying to be eggs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pb_banana_oatmeal', '{"id":"pb_banana_oatmeal","name":"Peanut butter banana oatmeal","emoji":"🥜","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts"],"time":10,"servings":2,"ing":[{"f":"oats","q":120},{"f":"banana","q":2},{"f":"peanut_butter","q":40},{"f":"cinnamon","q":2},{"f":"honey","q":15}],"steps":["Simmer the oats in 2 cups of water with a pinch of salt, stirring, 5 minutes.","Mash one banana straight into the pot — it sweetens and creams the oats.","Swirl in the peanut butter and cinnamon off the heat.","Slice the second banana over the top.","Finish with a thread of honey."],"tip":"Mashed banana does the work of milk and sugar in one move."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_chickpea_spinach_curry', '{"id":"coconut_chickpea_spinach_curry","name":"Coconut chickpea & spinach curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"coconut_milk","q":250},{"f":"spinach","q":120},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"curry_powder","q":10},{"f":"rice","q":140},{"f":"olive_oil","q":15}],"steps":["Start the rice. Fry the diced onion in the oil until golden, 6 minutes.","Add the garlic, ginger and curry powder; toast 1 minute.","Pour in the coconut milk and drained chickpeas; simmer 10 minutes until slightly thickened.","Stir in the spinach to wilt.","Season and serve over the rice."],"tip":"Simmer coconut milk gently — a hard boil splits it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_lentil_soup', '{"id":"lemon_lentil_soup","name":"Lemony Mediterranean lentil soup","emoji":"🍲","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"carrots","q":120},{"f":"celery","q":80},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"cumin","q":4},{"f":"lemon","q":1},{"f":"olive_oil","q":20}],"steps":["Soften the diced onion, carrot and celery in the oil over medium, 6 minutes.","Add the garlic and cumin for 1 minute.","Add the rinsed lentils and 4 cups of water; simmer 25 minutes until tender.","Blend half the pot (or mash roughly) for body, leaving the rest chunky.","Finish with the lemon’s juice and a swirl of olive oil — the lemon is not optional."],"tip":"Acid at the end is what separates restaurant lentil soup from sad lentil soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_tacos', '{"id":"sweet_potato_black_bean_tacos","name":"Roasted sweet potato & black bean tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":450},{"f":"black_beans","q":300},{"f":"tortillas","q":6},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 425°F. Toss the diced sweet potatoes with oil, chili powder and cumin; roast 25 minutes until browned at the edges.","Warm the beans with a splash of water and a pinch of salt.","Mash the avocado with the lime’s juice.","Char the tortillas in a dry skillet.","Build: avocado smear, beans, sweet potatoes, cilantro."],"tip":"Sweet + smoky + creamy is why nobody misses the meat here."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('quinoa_stuffed_peppers', '{"id":"quinoa_stuffed_peppers","name":"Quinoa-stuffed bell peppers","emoji":"🫑","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"bell_pepper","q":3},{"f":"quinoa","q":130},{"f":"black_beans","q":250},{"f":"corn_frozen","q":100},{"f":"crushed_tomatoes","q":200},{"f":"cumin","q":4},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Cook the quinoa. Heat the oven to 400°F.","Sauté the diced onion in oil, then stir in beans, corn, crushed tomatoes, cumin and the cooked quinoa; simmer 3 minutes.","Halve the peppers through the stem and seed them.","Pack the filling into the pepper halves, add a splash of water to the dish, cover with foil.","Bake 25 minutes covered, then 5 uncovered until the peppers are tender but standing."],"tip":"Halved peppers cook faster and hold more filling than the upright classic."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hummus_veggie_pita_pockets', '{"id":"hummus_veggie_pita_pockets","name":"Hummus & crunch pita pockets","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":10,"servings":2,"ing":[{"f":"pita","q":2},{"f":"hummus","q":160},{"f":"cucumber","q":1},{"f":"tomato","q":1},{"f":"romaine","q":0.5},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10}],"steps":["Halve the pitas and open the pockets.","Slice the cucumber and tomato thin; shred the romaine.","Toss the vegetables with lemon juice, olive oil and a pinch of salt.","Spread hummus generously inside each pocket.","Stuff with the dressed crunch and eat immediately."],"tip":"Dress the vegetables, not the bread — soggy pita is a preventable tragedy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_fried_rice', '{"id":"vegetable_fried_rice","name":"Ginger vegetable fried rice","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten"],"time":20,"servings":2,"ing":[{"f":"rice","q":180},{"f":"carrots","q":100},{"f":"peas_frozen","q":100},{"f":"corn_frozen","q":80},{"f":"scallions","q":0.5},{"f":"ginger","q":12},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"olive_oil","q":20}],"steps":["Use cold cooked rice if you have it; fresh rice should cool spread on a plate 10 minutes.","Stir-fry the diced carrots in the oil over high heat, 3 minutes.","Add peas, corn, ginger and garlic; fry 2 minutes more.","Add the rice, press flat, and let it sizzle untouched 1 minute before tossing.","Season with soy sauce, toss with scallions, serve hot."],"tip":"The untouched minute is where fried rice gets its toasty edges."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lentil_soup', '{"id":"coconut_lentil_soup","name":"Coconut red-spiced lentil soup","emoji":"🥥","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"coconut_milk","q":200},{"f":"crushed_tomatoes","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"curry_powder","q":10},{"f":"olive_oil","q":15},{"f":"lime","q":1}],"steps":["Soften the diced onion in the oil, 5 minutes; add garlic, ginger and curry powder for 1 minute.","Add the rinsed lentils, crushed tomatoes and 3 cups of water.","Simmer 20–25 minutes until the lentils collapse into the broth.","Stir in the coconut milk and warm through without boiling.","Brighten with lime juice and serve."],"tip":"Lentils + coconut is the highest comfort-per-dollar ratio in the kitchen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smashed_chickpea_avocado_toast', '{"id":"smashed_chickpea_avocado_toast","name":"Smashed chickpea avocado toast","emoji":"🥑","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":10,"servings":2,"ing":[{"f":"bread","q":4},{"f":"chickpeas","q":250},{"f":"avocado","q":1},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10},{"f":"black_pepper","q":1},{"f":"salt","q":2}],"steps":["Toast the bread properly — deep golden, not beige.","Fork-smash the drained chickpeas with the avocado, lemon juice, salt and pepper. Leave it chunky.","Pile onto the toast.","Finish with olive oil and more pepper.","Eat over a plate; this is structural-integrity-optional food."],"tip":"Chickpeas double the protein and make avocado toast an actual meal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_tofu_rice_bowl', '{"id":"peanut_tofu_rice_bowl","name":"Peanut-sauce tofu rice bowl","emoji":"🥣","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","nuts","gluten"],"time":30,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"peanut_butter","q":50},{"f":"soy_sauce","q":25},{"f":"lime","q":1},{"f":"honey","q":15},{"f":"garlic","q":0.2},{"f":"rice","q":160},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"olive_oil","q":15}],"steps":["Start the rice. Press and cube the tofu, then sear in the oil until golden on two sides, 8 minutes total.","Whisk the peanut butter with soy sauce, lime juice, honey, grated garlic and 3–4 tablespoons of hot water into a pourable sauce.","Ribbon the carrots with a peeler; slice the cucumber.","Toss the hot tofu in half the sauce to glaze.","Bowl the rice, tofu and vegetables; drizzle the rest of the sauce over."],"tip":"Hot water is the secret to a silky peanut sauce that doesn’t seize."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_tomato_ratatouille', '{"id":"zucchini_tomato_ratatouille","name":"Weeknight ratatouille skillet","emoji":"🍅","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free","low-carb"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"zucchini","q":2},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"crushed_tomatoes","q":400},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"olive_oil","q":25}],"steps":["Brown the sliced zucchini hard in half the oil over medium-high, 5 minutes; set aside.","Soften the sliced onion and pepper in the rest of the oil, 5 minutes.","Add the garlic and oregano, then the crushed tomatoes; simmer 10 minutes.","Return the zucchini and simmer 5 more, until everything is silky but not mush.","Tear in the basil and serve — alone, over rice, or under a fried egg."],"tip":"Browning the zucchini separately keeps it from watering down the stew."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mexican_rice_bean_skillet', '{"id":"mexican_rice_bean_skillet","name":"One-pan Mexican rice & beans","emoji":"🍳","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"rice","q":160},{"f":"black_beans","q":300},{"f":"salsa","q":200},{"f":"corn_frozen","q":100},{"f":"onion","q":0.5},{"f":"cumin","q":4},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Soften the diced onion in the oil with the cumin, 3 minutes.","Stir in the rice to coat, then add the salsa and 1½ cups of water.","Cover and simmer low 15 minutes.","Scatter the beans and corn on top, cover again 5 minutes until the rice is tender.","Fluff, fold everything together, finish with lime and cilantro."],"tip":"The salsa is doing the work of six ingredients — buy one you would eat with a spoon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_quinoa_pilaf', '{"id":"mushroom_quinoa_pilaf","name":"Mushroom & spinach quinoa pilaf","emoji":"🍄","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"quinoa","q":150},{"f":"mushrooms","q":250},{"f":"spinach","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5}],"steps":["Cook the quinoa in salted water, 15 minutes, and fluff.","Meanwhile brown the sliced mushrooms in the oil over medium-high — crowd them less than feels natural — 6 minutes.","Add the diced onion and garlic; soften 3 minutes.","Fold in the spinach to wilt, then the quinoa.","Season and finish with lemon juice."],"tip":"Mushrooms brown only after their water burns off — patience, then flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_chili', '{"id":"sweet_potato_chili","name":"Smoky sweet potato & bean chili","emoji":"🍠","cuisine":"American","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":400},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"chili_powder","q":10},{"f":"cumin","q":5},{"f":"corn_frozen","q":100},{"f":"olive_oil","q":15}],"steps":["Soften the diced onion in the oil, 4 minutes; add garlic and the spices for 1 minute.","Add the diced sweet potatoes, crushed tomatoes and 2 cups of water.","Simmer 20 minutes until the sweet potato is fork-tender.","Add the beans and corn; simmer 5 more minutes.","Mash a few sweet potato chunks against the pot to thicken, season, serve."],"tip":"Sweet potato rounds out chili heat the way sugar never quite does."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('apple_cinnamon_oatmeal', '{"id":"apple_cinnamon_oatmeal","name":"Apple pie oatmeal","emoji":"🍎","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":[],"time":15,"servings":2,"ing":[{"f":"oats","q":120},{"f":"apple","q":2},{"f":"cinnamon","q":3},{"f":"honey","q":20},{"f":"almonds","q":30}],"steps":["Dice one apple and simmer it in 2 cups of water with the cinnamon, 3 minutes.","Add the oats and a pinch of salt; simmer 5 minutes, stirring.","Grate the second apple straight into the pot and stir through.","Sweeten with honey to taste.","Top with roughly chopped almonds for crunch."],"tip":"Grated apple melts into the oats; diced apple stays tender-crisp — using both is the trick."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_chickpea_greek_salad', '{"id":"crispy_chickpea_greek_salad","name":"Crispy chickpea Greek salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":140},{"f":"onion","q":0.3},{"f":"oregano","q":3},{"f":"lemon","q":1},{"f":"olive_oil","q":25}],"steps":["Dry the chickpeas well, then crisp them in half the oil in a skillet with the oregano and a pinch of salt, 8–10 minutes.","Chop the romaine, cucumber and halve the tomatoes; shave the onion thin.","Whisk the lemon juice with the remaining oil.","Toss the vegetables with the dressing.","Top with the hot, crackly chickpeas and eat while they still crunch."],"tip":"Hot-on-cold is the move — warm chickpeas soften the onion’s bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_sweet_potato_soup', '{"id":"coconut_sweet_potato_soup","name":"Coconut-ginger sweet potato soup","emoji":"🍜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"coconut_milk","q":250},{"f":"ginger","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Soften the diced onion in the oil, 5 minutes; add the garlic and grated ginger for 1 minute.","Add the peeled, cubed sweet potatoes and 2½ cups of water; simmer 18 minutes until completely tender.","Blend smooth (an immersion blender straight in the pot is easiest).","Stir in the coconut milk and reheat gently.","Season and finish each bowl with a hard squeeze of lime."],"tip":"Ginger and lime keep a sweet soup savory — don’t skimp on either."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_butter_shrimp_zucchini', '{"id":"garlic_butter_shrimp_zucchini","name":"Garlic-butter shrimp & zucchini","emoji":"🍤","cuisine":"American","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["shellfish","dairy"],"time":15,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"zucchini","q":2},{"f":"butter","q":30},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"black_pepper","q":1},{"f":"salt","q":2}],"steps":["Halve the zucchini lengthwise and slice into half-moons; pat the shrimp very dry.","Brown the zucchini in half the butter over medium-high, 4 minutes; push to the side.","Add the rest of the butter and the shrimp in one layer; cook 90 seconds per side.","Add the sliced garlic for the final minute — it should sizzle, not scorch.","Kill the heat, season, and finish with lemon juice, scraping up the pan butter."],"tip":"Shrimp are done the instant they curl into loose Cs — tight Os are overcooked."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_pepper_chicken_broccoli', '{"id":"lemon_pepper_chicken_broccoli","name":"Lemon-pepper chicken & charred broccoli","emoji":"🍋","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"broccoli","q":450},{"f":"lemon","q":1},{"f":"black_pepper","q":3},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25},{"f":"salt","q":3}],"steps":["Slice the chicken into cutlets; rub with half the oil, the lemon zest, plenty of black pepper and salt.","Sear over medium-high, 3–4 minutes per side, until cooked through; rest.","Char the broccoli florets in the remaining oil in the same hot pan, 5 minutes, adding the sliced garlic at the end.","Splash in 2 tablespoons of water and cover 1 minute to steam-finish.","Serve everything doused with the lemon’s juice."],"tip":"Zest in the rub, juice at the end — lemon twice, two different jobs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('burger_bowls', '{"id":"burger_bowls","name":"Loaded burger bowls","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":20,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"romaine","q":1},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"cheddar","q":60},{"f":"avocado","q":1},{"f":"sour_cream","q":40},{"f":"olive_oil","q":10}],"steps":["Season the beef and brown it in the oil in crumbles, undisturbed at first for crust, 6–7 minutes.","Melt the cheddar over the beef in the pan.","Chop the romaine, dice the tomato, shave the onion, slice the avocado.","Build bowls on the lettuce with the cheesy beef and vegetables.","Thin the sour cream with a splash of water and drizzle over as the “special sauce.”"],"tip":"Everything you like about a burger, minus the part that was mostly filler anyway."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_avocado_salad', '{"id":"salmon_avocado_salad","name":"Seared salmon & avocado salad","emoji":"🐟","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["fish"],"time":20,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":20}],"steps":["Season the salmon and sear skin-side down 4 minutes, flip for 2, then rest.","Chop the romaine and cucumber; slice the avocado.","Whisk the lemon juice into the olive oil with salt and pepper.","Toss the greens in most of the dressing.","Flake the warm salmon over the top and spoon on the rest of the dressing."],"tip":"Warm fish on cold crisp greens is a temperature trick worth stealing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_shrimp_stirfry', '{"id":"ginger_shrimp_stirfry","name":"Ginger-garlic shrimp stir-fry","emoji":"🦐","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","low-carb","high-protein"],"allergens":["shellfish","soy","gluten"],"time":15,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"broccoli","q":450},{"f":"bell_pepper","q":1},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":25},{"f":"scallions","q":0.5},{"f":"olive_oil","q":20}],"steps":["Get the pan properly hot. Stir-fry the broccoli florets and sliced pepper in half the oil, 4 minutes; set aside.","Add the rest of the oil and the dried shrimp in one layer; 90 seconds per side.","Add the ginger and garlic for 30 seconds.","Return the vegetables with the soy sauce and toss hard for 1 minute.","Finish with sliced scallions."],"tip":"Stir-fry is 80% prep, 20% cooking — everything cut and within reach before the flame."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_parm_salad', '{"id":"chicken_parm_salad","name":"Grilled chicken & parmesan romaine salad","emoji":"🥬","cuisine":"Italian","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"romaine","q":1},{"f":"parmesan","q":40},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"garlic","q":0.1},{"f":"black_pepper","q":2}],"steps":["Pound the chicken even, season, and grill or sear 4 minutes per side; rest and slice.","Whisk the lemon juice, grated garlic and plenty of black pepper into the olive oil.","Chop the romaine into wide ribbons.","Toss the leaves with the dressing and most of the parmesan.","Top with the sliced chicken and the rest of the cheese."],"tip":"Lemon + parmesan + pepper gets you 90% of a Caesar with zero raw-egg logistics."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('taco_stuffed_avocados', '{"id":"taco_stuffed_avocados","name":"Taco-stuffed avocados","emoji":"🥑","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"avocado","q":2},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"salsa","q":120},{"f":"cilantro","q":0.2},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Brown the turkey in the oil with the chili powder and cumin, 6–7 minutes.","Stir in half the salsa and simmer 2 minutes until saucy.","Halve and pit the avocados; scoop a little extra from each half to widen the bowl (eat the scoops — chef’s tax).","Pile the taco meat into the avocado halves.","Top with the remaining salsa, cilantro and lime."],"tip":"The avocado IS the tortilla. No notes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_muffin_cups', '{"id":"egg_muffin_cups","name":"Meal-prep egg muffin cups","emoji":"🧁","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":8},{"f":"bell_pepper","q":1},{"f":"spinach","q":60},{"f":"cheddar","q":60},{"f":"scallions","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 375°F and oil a muffin tin well.","Whisk the eggs with salt and pepper.","Divide the diced pepper, chopped spinach, scallions and cheddar among 8–10 cups.","Pour the egg over, filling each cup three-quarters.","Bake 18–20 minutes until puffed and set. They keep 4 days refrigerated."],"tip":"They deflate as they cool — that’s physics, not failure."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_burrito_bowl', '{"id":"chicken_burrito_bowl","name":"Chipotle-style chicken burrito bowl","emoji":"🍗","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"rice","q":160},{"f":"black_beans","q":250},{"f":"salsa","q":150},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"olive_oil","q":15}],"steps":["Cook the rice; fold in lime zest and half the juice with the chopped cilantro stems.","Rub the chicken with chili powder, cumin and salt; sear in the oil 4–5 minutes per side, rest, slice.","Warm the beans with a splash of their liquid.","Build bowls: cilantro-lime rice, beans, chicken.","Top with salsa, cilantro leaves, and the last of the lime."],"tip":"Thighs forgive the extra minute that breasts punish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_broccoli_rice', '{"id":"beef_broccoli_rice","name":"Takeout-style beef & broccoli","emoji":"🥡","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["soy","gluten"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"broccoli","q":450},{"f":"soy_sauce","q":35},{"f":"honey","q":15},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"rice","q":160},{"f":"olive_oil","q":15}],"steps":["Start the rice. Stir the soy sauce, honey, and 3 tablespoons of water into a sauce.","Brown the beef hard in the oil, breaking it into large crumbles, 5 minutes; push aside.","Add the broccoli florets with a splash of water; cover 2 minutes to steam.","Add the garlic and ginger, then the sauce; toss everything 2 minutes until glossy.","Serve over the rice."],"tip":"Ground beef gives you all the flavor of the takeout classic in a third of the time and cost."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_meatballs_marinara', '{"id":"turkey_meatballs_marinara","name":"Turkey meatballs in marinara","emoji":"🧆","cuisine":"Italian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","eggs"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"oats","q":40},{"f":"eggs","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"basil","q":0.3},{"f":"spaghetti","q":160},{"f":"olive_oil","q":15}],"steps":["Blitz the oats to a rough flour. Mix with the turkey, egg, half the minced garlic and a big pinch of salt; roll into 12 meatballs.","Brown the meatballs in the oil on two sides, 5 minutes total — they finish in the sauce.","Add the rest of the garlic, then the crushed tomatoes; simmer 15 minutes, turning the meatballs once.","Cook the spaghetti meanwhile in salted water.","Toss pasta with sauce, top with meatballs and torn basil."],"tip":"Oats disappear as a binder and keep lean turkey juicy — nobody will guess."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_quinoa_power_bowl', '{"id":"salmon_quinoa_power_bowl","name":"Salmon quinoa power bowl","emoji":"💪","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":25,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"quinoa","q":140},{"f":"spinach","q":80},{"f":"avocado","q":1},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":20}],"steps":["Cook the quinoa; fluff and season while warm.","Sear the seasoned salmon 4 minutes skin-side, 2 on the flesh; rest and flake.","Wilt the spinach into the warm quinoa — residual heat does it.","Slice the avocado and cucumber.","Bowl everything and dress with lemon juice whisked into the olive oil."],"tip":"Seasoning grains while warm means half the dressing does twice the work."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_tortilla_soup', '{"id":"chicken_tortilla_soup","name":"Chicken tortilla soup","emoji":"🍲","cuisine":"Mexican","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"broth","q":750},{"f":"salsa","q":200},{"f":"corn_frozen","q":100},{"f":"tortillas","q":3},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"cumin","q":4},{"f":"olive_oil","q":15}],"steps":["Cut two tortillas into strips, toss with a little oil, and crisp in a skillet or 400°F oven, 8 minutes.","Simmer the chicken in the broth with the salsa, cumin and the third tortilla torn in (it melts and thickens), 15 minutes.","Shred the chicken back into the pot with the corn; simmer 3 minutes.","Season and hit hard with lime.","Serve topped with cilantro and the crispy strips."],"tip":"The dissolved tortilla is the traditional thickener — no cream, no flour."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_pasta', '{"id":"caprese_pasta","name":"Warm caprese pasta","emoji":"🍅","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"spaghetti","q":200},{"f":"cherry_tomatoes","q":280},{"f":"mozzarella","q":120},{"f":"basil","q":0.4},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25}],"steps":["Cook the pasta in aggressively salted water.","Meanwhile, halve the tomatoes and warm them in the oil with the sliced garlic over medium until they just slump, 4 minutes.","Drag the pasta into the tomatoes with a splash of pasta water; toss 1 minute.","Off heat, fold in the torn mozzarella so it goes creamy at the edges but keeps its shape.","Shower with basil, salt, and a final thread of oil."],"tip":"Off-heat mozzarella is the difference between creamy and squeaky."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_mushroom_quesadillas', '{"id":"spinach_mushroom_quesadillas","name":"Spinach-mushroom quesadillas","emoji":"🫓","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"cheddar","q":120},{"f":"mushrooms","q":200},{"f":"spinach","q":80},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"salsa","q":100}],"steps":["Brown the sliced mushrooms and onion in the oil until dry and golden, 6 minutes; wilt in the spinach and season.","Layer cheddar, the vegetables, and more cheddar over half of each tortilla; fold.","Toast in a dry skillet over medium, 2–3 minutes per side, pressing gently.","Rest one minute — molten cheese needs to set from lava to fudge.","Cut into wedges and serve with salsa."],"tip":"Cheese on both sides of the filling is the glue that keeps quesadillas together."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tomato_soup_grilled_cheese', '{"id":"tomato_soup_grilled_cheese","name":"Tomato-basil soup & grilled cheese","emoji":"🥪","cuisine":"American","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"crushed_tomatoes","q":500},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"basil","q":0.3},{"f":"bread","q":4},{"f":"cheddar","q":100},{"f":"butter","q":20},{"f":"olive_oil","q":10}],"steps":["Soften the diced onion in the olive oil, add the garlic, then the crushed tomatoes and 1 cup of water; simmer 15 minutes.","Blend smooth with most of the basil.","Butter the bread on the outside, cheddar inside; toast in a skillet over medium-low, 3–4 minutes per side, lid on for the first flip.","Rest the sandwiches a minute, then halve on the diagonal (mandatory).","Serve with the soup for dunking."],"tip":"Low and slow gets the cheese melted before the bread burns — the lid is the cheat code."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_baked_sweet_potatoes', '{"id":"loaded_baked_sweet_potatoes","name":"Loaded baked sweet potatoes","emoji":"🍠","cuisine":"American","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"sweet_potatoes","q":600},{"f":"black_beans","q":250},{"f":"greek_yogurt","q":100},{"f":"cheddar","q":60},{"f":"scallions","q":0.5},{"f":"chili_powder","q":4},{"f":"lime","q":0.5}],"steps":["Bake the sweet potatoes at 425°F until a knife slides through, 40–45 minutes (or microwave 8, then oven 10 for real skin).","Warm the beans with the chili powder and a splash of water.","Split the potatoes and fluff the insides with a fork and a pinch of salt.","Load with beans and cheddar so it melts into the flesh.","Top with lime-spiked yogurt and sliced scallions."],"tip":"Greek yogurt out-sours sour cream and smuggles in protein."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pita_margherita_pizzas', '{"id":"pita_margherita_pizzas","name":"Pita margherita pizzas","emoji":"🍕","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":15,"servings":2,"ing":[{"f":"pita","q":3},{"f":"crushed_tomatoes","q":150},{"f":"mozzarella","q":150},{"f":"basil","q":0.3},{"f":"oregano","q":2},{"f":"olive_oil","q":15},{"f":"garlic","q":0.1}],"steps":["Heat the oven to 475°F with a baking sheet inside.","Stir the grated garlic and oregano into the crushed tomatoes with a pinch of salt.","Sauce the pitas edge to edge, then tear the mozzarella over.","Slide onto the hot sheet and bake 7–8 minutes until blistered.","Basil and olive oil the moment they come out."],"tip":"The preheated sheet is your pizza stone — crisp bottom, no gear."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bean_breakfast_burritos', '{"id":"bean_breakfast_burritos","name":"Black bean breakfast burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["gluten","eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":2},{"f":"eggs","q":4},{"f":"black_beans","q":200},{"f":"cheddar","q":60},{"f":"salsa","q":100},{"f":"butter","q":10},{"f":"scallions","q":0.3}],"steps":["Warm the beans; scramble the eggs soft in the butter with the scallions.","Warm the tortillas until pliable.","Lay down cheddar first (so it melts), then eggs, beans and salsa, slightly below center.","Fold the sides in, then roll tight from the bottom.","Seal seam-down in the hot pan 1 minute per side. Wrapped in foil, they survive commutes and freezers."],"tip":"The pan-seal is what separates a burrito from a pile."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('herb_roasted_chicken_potatoes', '{"id":"herb_roasted_chicken_potatoes","name":"Sheet-pan herb chicken & potatoes","emoji":"🍗","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"potatoes","q":500},{"f":"olive_oil","q":25},{"f":"oregano","q":3},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"salt","q":4}],"steps":["Heat the oven to 425°F. Halve the baby-cut potatoes (or chunk large ones).","Toss potatoes and chicken with the oil, oregano, minced garlic and salt on a sheet pan.","Arrange skin-side up with space between pieces — crowding steams, spacing roasts.","Roast 35 minutes until the chicken hits crisp and the potatoes are golden.","Squeeze the lemon over the whole pan before serving."],"tip":"One pan, one cutting board, one lemon — weeknight math that works."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_potato_hash', '{"id":"beef_potato_hash","name":"Crispy beef & potato skillet hash","emoji":"🥔","cuisine":"American","meal":["dinner","breakfast"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"potatoes","q":450},{"f":"onion","q":0.5},{"f":"bell_pepper","q":1},{"f":"chili_powder","q":4},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Dice the potatoes small and get them crisping in the oil over medium-high, tossing every few minutes, 12–15 minutes.","Push aside; brown the beef in the middle, 5 minutes.","Add the diced onion and pepper with the chili powder; cook 4 minutes.","Fold everything together and let it sit untouched 2 minutes for a final crust.","Season and serve — a fried egg on top converts it to breakfast."],"tip":"Small dice and patience are the whole secret to crispy skillet potatoes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_lime_chicken_rice', '{"id":"honey_lime_chicken_rice","name":"Honey-lime skillet chicken & rice","emoji":"🍯","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"honey","q":25},{"f":"lime","q":2},{"f":"garlic","q":0.3},{"f":"rice","q":160},{"f":"cilantro","q":0.3},{"f":"chili_powder","q":4},{"f":"olive_oil","q":15}],"steps":["Start the rice. Whisk the honey with the juice of both limes, the garlic and chili powder.","Sear the seasoned chicken in the oil, 4–5 minutes per side.","Pour the honey-lime over the chicken and let it bubble to a glaze, 2 minutes, turning to coat.","Rest the chicken briefly, then slice.","Serve over rice with the pan glaze and cilantro."],"tip":"Honey burns fast — the glaze goes in only after the chicken is basically done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlicky_beans_greens_toast', '{"id":"garlicky_beans_greens_toast","name":"Garlicky beans & greens on toast","emoji":"🍞","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":15,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"spinach","q":150},{"f":"garlic","q":0.4},{"f":"bread","q":4},{"f":"olive_oil","q":30},{"f":"lemon","q":0.5},{"f":"oregano","q":2}],"steps":["Sizzle the sliced garlic in the oil over medium-low until pale gold — not brown — 2 minutes.","Add the chickpeas with a splash of their liquid and the oregano; simmer 5 minutes, mashing a third of them.","Fold in the spinach to wilt.","Toast the bread dark and rub it with the cut lemon.","Pile the beans on the toast and finish with lemon juice and oil."],"tip":"Beans on toast, Mediterranean edition — pantry dinner with dignity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_avocado_rice_bowls', '{"id":"shrimp_avocado_rice_bowls","name":"Chili-lime shrimp & avocado rice bowls","emoji":"🍤","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"rice","q":160},{"f":"avocado","q":1},{"f":"lime","q":2},{"f":"chili_powder","q":6},{"f":"cilantro","q":0.3},{"f":"corn_frozen","q":100},{"f":"olive_oil","q":15}],"steps":["Cook the rice; fold in the zest and juice of one lime.","Char the corn in a dry skillet, 3 minutes; set aside.","Toss the dried shrimp with chili powder and salt; sear in the oil 90 seconds per side.","Slice the avocado.","Bowl the rice, corn, shrimp and avocado; finish with the second lime and cilantro."],"tip":"Dry shrimp sear; wet shrimp steam. A paper towel is the best marinade."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pepper_egg_breakfast_tacos', '{"id":"pepper_egg_breakfast_tacos","name":"Charred pepper & egg breakfast tacos","emoji":"🌮","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian","dairy-free"],"allergens":["gluten","eggs"],"time":15,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"eggs","q":5},{"f":"bell_pepper","q":1},{"f":"onion","q":0.3},{"f":"salsa","q":100},{"f":"cilantro","q":0.2},{"f":"olive_oil","q":15}],"steps":["Char the sliced pepper and onion in the oil over high heat, 4 minutes, until blistered at the edges.","Drop to medium-low, pour in the whisked eggs, and scramble soft through the vegetables.","Toast the tortillas over the flame or in a dry pan.","Fill with the eggs.","Top with salsa and cilantro."],"tip":"Charred peppers do for eggs what bacon usually gets credit for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_salmon_pasta', '{"id":"lemon_garlic_salmon_pasta","name":"Lemon-garlic salmon pasta","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["fish","gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"spaghetti","q":180},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"spinach","q":80},{"f":"parmesan","q":30},{"f":"olive_oil","q":25},{"f":"black_pepper","q":2}],"steps":["Cook the spaghetti; reserve a cup of pasta water.","Sear the salmon in the oil 3 minutes per side; remove and flake.","Soften the sliced garlic in the same pan, 1 minute.","Toss in the pasta, spinach, lemon zest and juice with splashes of pasta water until glossy.","Fold the salmon back in gently, finish with parmesan and black pepper."],"tip":"Flaked fish folded in at the end stays in pieces instead of becoming sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('veggie_rice_noodle_stirfry', '{"id":"veggie_rice_noodle_stirfry","name":"Pad-thai-style rice noodles","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","soy","nuts","gluten"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":180},{"f":"eggs","q":2},{"f":"carrots","q":100},{"f":"scallions","q":0.5},{"f":"peanut_butter","q":30},{"f":"soy_sauce","q":30},{"f":"lime","q":1},{"f":"honey","q":15},{"f":"olive_oil","q":15}],"steps":["Soak the rice noodles in just-boiled water until pliable but underdone, 6–7 minutes; drain.","Whisk the peanut butter, soy sauce, lime juice, honey and a splash of hot water into a sauce.","Scramble the eggs in the oil over high heat; add the ribboned carrots for 1 minute.","Add the noodles and sauce; toss 2 minutes until glossy and just tender.","Finish with scallions and extra lime."],"tip":"Undercook the soak — the noodles finish in the pan and stay springy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cashew_chicken', '{"id":"cashew_chicken","name":"Cashew chicken","emoji":"🥜","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["soy","nuts","gluten"],"time":25,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"cashews","q":70},{"f":"bell_pepper","q":1},{"f":"soy_sauce","q":35},{"f":"honey","q":15},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"rice","q":160},{"f":"olive_oil","q":15}],"steps":["Start the rice. Toast the cashews in the dry pan until golden; set aside.","Stir-fry the diced chicken in the oil over high heat until browned, 5–6 minutes.","Add the diced pepper, garlic and ginger; 2 minutes more.","Add the soy sauce and honey; let it bubble to a glaze, 1 minute.","Toss the cashews back in and serve over rice."],"tip":"Toasting the cashews separately keeps them crunchy against the glaze."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('edamame_fried_rice', '{"id":"edamame_fried_rice","name":"Sesame edamame fried rice","emoji":"🫛","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","sesame","gluten"],"time":20,"servings":2,"ing":[{"f":"rice","q":180},{"f":"edamame_frozen","q":250},{"f":"carrots","q":80},{"f":"scallions","q":0.5},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":10}],"steps":["Cold cooked rice works best; make it ahead if you can.","Stir-fry the diced carrots in the neutral oil over high heat, 2 minutes.","Add the edamame straight from frozen with the garlic and ginger; 2 minutes more.","Add the rice, press it into the pan, and let it crackle before tossing with the soy sauce.","Kill the heat, finish with sesame oil and scallions — sesame is a finishing oil, not a frying oil."],"tip":"Edamame makes this a complete protein without anything having had a face."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_cabbage_stirfry', '{"id":"beef_cabbage_stirfry","name":"Ginger beef & cabbage stir-fry","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","low-carb","high-protein"],"allergens":["soy","sesame","gluten"],"time":20,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"cabbage","q":0.5},{"f":"carrots","q":80},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"scallions","q":0.5},{"f":"olive_oil","q":10}],"steps":["Brown the beef hard in the neutral oil, breaking it up, 5 minutes; push aside.","Add the thinly sliced cabbage and ribboned carrot; stir-fry 4 minutes until wilted but still squeaky.","Add the ginger and garlic for 1 minute.","Season with soy sauce and toss everything together.","Finish off-heat with sesame oil and scallions."],"tip":"Egg-roll filling as a bowl — everything you like about takeout minus the deep fryer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_fried_rice', '{"id":"cauliflower_fried_rice","name":"Cauliflower fried \"rice\"","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegetarian","dairy-free","low-carb"],"allergens":["eggs","soy","sesame","gluten"],"time":20,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"eggs","q":3},{"f":"peas_frozen","q":100},{"f":"scallions","q":0.5},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"soy_sauce","q":25},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15}],"steps":["Grate the cauliflower on the big holes (or pulse in a processor) into rice-sized bits.","Scramble the eggs in the oil over high heat; set aside.","Stir-fry the cauliflower with the garlic and ginger, 4–5 minutes — let it catch some color and drive off moisture.","Add the peas and soy sauce for 2 minutes; fold the eggs back in.","Finish with sesame oil and scallions."],"tip":"Dry pan, high heat: wet cauliflower is the only way this goes wrong."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('aloo_gobi', '{"id":"aloo_gobi","name":"Aloo gobi","emoji":"🥔","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"potatoes","q":400},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"turmeric","q":4},{"f":"cumin","q":4},{"f":"garam_masala","q":4},{"f":"ginger","q":10},{"f":"olive_oil","q":25},{"f":"cilantro","q":0.3}],"steps":["Brown the diced potatoes in the oil over medium, lid on, stirring occasionally, 8 minutes.","Add the cauliflower florets, diced onion, ginger, turmeric and cumin; toss to stain everything gold.","Add the chopped tomatoes and a splash of water; cover and cook 12 minutes until tender.","Uncover, raise the heat, and let the edges catch a little.","Finish with garam masala and cilantro — the masala goes in last, that is the technique."],"tip":"Garam masala added at the end stays aromatic; cooked long it just goes flat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('kale_chickpea_saag_style', '{"id":"kale_chickpea_saag_style","name":"Saag-style creamy greens & chickpeas","emoji":"🥬","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"kale","q":1},{"f":"spinach","q":150},{"f":"chickpeas","q":250},{"f":"coconut_milk","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"garam_masala","q":5},{"f":"cumin","q":4},{"f":"rice","q":140},{"f":"olive_oil","q":15}],"steps":["Start the rice. Soften the diced onion in the oil until golden, 6 minutes; add garlic, ginger and cumin for 1 minute.","Add the stripped, chopped kale with a splash of water; cover 4 minutes until collapsed.","Add the spinach to wilt, then blend the greens roughly right in the pot.","Stir in the chickpeas and coconut milk; simmer 5 minutes.","Finish with garam masala and serve over rice."],"tip":"Blending half-smooth is the saag texture — creamy but still recognizably greens."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_style_yogurt_chicken', '{"id":"tandoori_style_yogurt_chicken","name":"Tandoori-style yogurt chicken","emoji":"🍗","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"greek_yogurt","q":150},{"f":"garam_masala","q":6},{"f":"turmeric","q":3},{"f":"paprika","q":4},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"lemon","q":1},{"f":"olive_oil","q":10}],"steps":["Stir the yogurt with the garam masala, turmeric, paprika, grated garlic, ginger, half the lemon’s juice and a big pinch of salt.","Coat the chicken and marinate 15 minutes on the counter (or up to a day in the fridge).","Heat the broiler with a rack near the top; oil a foil-lined sheet.","Broil the chicken 6–7 minutes per side until charred in spots and cooked through.","Rest briefly, squeeze the rest of the lemon over, and serve — a cucumber salad on the side is traditional and correct."],"tip":"Yogurt tenderizes and chars where plain marinades just drip off — the broiler is your tandoor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_pulao', '{"id":"vegetable_pulao","name":"Vegetable pulao with cashews","emoji":"🍛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":["nuts"],"time":30,"servings":2,"ing":[{"f":"rice","q":180},{"f":"carrots","q":100},{"f":"peas_frozen","q":100},{"f":"onion","q":1},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"garam_masala","q":3},{"f":"cashews","q":50},{"f":"olive_oil","q":20}],"steps":["Toast the cashews in the dry pot until golden; set aside.","Fry the sliced onion in the oil until deeply golden, 8 minutes — this is the flavor base.","Stir in the cumin, turmeric and rice to coat every grain.","Add the diced carrots and 1¾ cups water; cover and simmer low 15 minutes, adding the peas for the last 5.","Rest 5 minutes off heat, fluff, and finish with garam masala and the cashews."],"tip":"Coating the rice in spiced oil before the water goes in is what makes pulao taste like pulao."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_bhurji', '{"id":"egg_bhurji","name":"Egg bhurji (Indian scrambled eggs)","emoji":"🍳","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs"],"time":15,"servings":2,"ing":[{"f":"eggs","q":5},{"f":"onion","q":0.5},{"f":"tomato","q":1},{"f":"turmeric","q":2},{"f":"cumin","q":2},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Soften the finely diced onion in the oil over medium, 3 minutes.","Add the cumin and turmeric for 30 seconds, then the diced tomato until it slumps, 2 minutes.","Pour in the whisked, salted eggs.","Scramble in small curds, stopping while still glossy.","Shower with cilantro and serve — with toast, or wrapped in a warm tortilla."],"tip":"Bhurji is proof that scrambled eggs were never the ceiling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_chickpea_curry', '{"id":"cauliflower_chickpea_curry","name":"Cauliflower & chickpea curry","emoji":"🥘","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"chickpeas","q":250},{"f":"coconut_milk","q":250},{"f":"crushed_tomatoes","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"curry_powder","q":10},{"f":"garam_masala","q":3},{"f":"rice","q":140},{"f":"olive_oil","q":15}],"steps":["Start the rice. Golden the diced onion in the oil, then bloom the curry powder with the garlic, 1 minute.","Add the crushed tomatoes; cook 3 minutes.","Add the cauliflower florets, chickpeas, coconut milk and a splash of water; cover and simmer 15 minutes.","Uncover and reduce 3 minutes until the sauce coats the florets.","Finish with garam masala; serve over rice."],"tip":"Cauliflower drinks curry sauce like it was designed for the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_feta_tomato_pasta', '{"id":"baked_feta_tomato_pasta","name":"Baked feta & burst tomato pasta","emoji":"🧀","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"feta","q":170},{"f":"cherry_tomatoes","q":560},{"f":"spaghetti","q":180},{"f":"garlic","q":0.3},{"f":"basil","q":0.3},{"f":"olive_oil","q":30},{"f":"oregano","q":2}],"steps":["Heat the oven to 400°F. Put the feta block in the middle of a baking dish, tomatoes around it, everything doused in the oil and oregano.","Bake 30 minutes until the tomatoes burst and the feta browns on top.","Cook the spaghetti meanwhile; reserve pasta water.","Mash the feta and tomatoes into a sauce with the roasted garlic.","Toss with the pasta, loosening with pasta water, and finish with basil."],"tip":"Yes, it is the viral one — it went viral because it works."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('massaged_kale_feta_salad', '{"id":"massaged_kale_feta_salad","name":"Massaged kale salad with feta & walnuts","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy","nuts"],"time":15,"servings":2,"ing":[{"f":"kale","q":1},{"f":"feta","q":70},{"f":"walnuts","q":50},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"honey","q":10},{"f":"apple","q":1}],"steps":["Strip the kale from its stems, tear into pieces, and — really — massage it with a pinch of salt and half the oil for 2 minutes until it darkens and softens.","Toast the walnuts in a dry pan, 3 minutes.","Whisk the lemon juice, remaining oil and honey.","Slice the apple thin.","Toss everything with the dressing and crumble the feta over."],"tip":"Massaging isn’t a food-blog affectation — it breaks down the fibers that make raw kale a chore."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_saganaki', '{"id":"shrimp_saganaki","name":"Shrimp saganaki (tomato & feta skillet)","emoji":"🍤","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"crushed_tomatoes","q":350},{"f":"feta","q":100},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"oregano","q":3},{"f":"olive_oil","q":20}],"steps":["Soften the diced onion in the oil; add the garlic and oregano for 1 minute.","Add the crushed tomatoes and simmer 10 minutes until thick.","Nestle the dried shrimp into the sauce; cook 2 minutes per side.","Crumble the feta over and cover 1 minute to soften it.","Finish with more oregano and eat straight from the pan with bread or over greens."],"tip":"The feta half-melts into salty cream pockets — that is the whole dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_chickpea_stew', '{"id":"eggplant_chickpea_stew","name":"Eggplant & chickpea stew","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"chickpeas","q":400},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"paprika","q":3},{"f":"olive_oil","q":30}],"steps":["Brown the cubed eggplant in most of the oil over medium-high until golden, 8 minutes; set aside.","Soften the diced onion, then add the garlic, oregano and paprika for 1 minute.","Add the crushed tomatoes and chickpeas; simmer 10 minutes.","Return the eggplant and simmer 10 more until silky.","Rest 5 minutes — this stew is better warm than hot, and better tomorrow than today."],"tip":"Eggplant browned first holds its shape; eggplant stewed raw dissolves into sludge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_tuna_salad', '{"id":"mediterranean_tuna_salad","name":"Mediterranean tuna & olive salad","emoji":"🐟","cuisine":"Mediterranean","meal":["lunch"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["fish"],"time":10,"servings":2,"ing":[{"f":"tuna_canned","q":284},{"f":"olives","q":60},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.2},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"oregano","q":2}],"steps":["Drain the tuna and flake it into a bowl in big pieces.","Dice the cucumber and tomatoes; sliver the onion; halve the olives.","Whisk the lemon juice, olive oil and oregano.","Fold everything together gently — the tuna should stay chunky.","Season with pepper (the olives bring the salt) and serve, alone or in a pita."],"tip":"No mayo, no apology — this is what tuna salad looks like on the Aegean."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_potatoes_green_beans', '{"id":"spanish_potatoes_green_beans","name":"Smoky Spanish potatoes & green beans","emoji":"🥔","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"potatoes","q":500},{"f":"green_beans","q":250},{"f":"paprika","q":5},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"crushed_tomatoes","q":150},{"f":"olive_oil","q":30}],"steps":["Crisp the diced potatoes in the oil over medium, tossing every few minutes, 15 minutes.","Add the onion and trimmed green beans; cook 4 minutes.","Add the garlic and smoked paprika for 30 seconds — off the heat briefly so the paprika doesn’t scorch.","Stir in the crushed tomatoes and simmer 3 minutes to a clingy sauce.","Season well; a fried egg on top is optional and excellent."],"tip":"Smoked paprika burns bitter in seconds — bloom it in oil off the flame."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_tenderloin_green_beans', '{"id":"pork_tenderloin_green_beans","name":"Garlic-herb pork tenderloin & green beans","emoji":"🥩","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":500},{"f":"green_beans","q":300},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"paprika","q":3},{"f":"lemon","q":0.5},{"f":"olive_oil","q":25},{"f":"salt","q":4}],"steps":["Heat the oven to 425°F. Rub the pork with oil, minced garlic, oregano, paprika and salt.","Sear it in an ovenproof skillet on all sides, 5 minutes total.","Scatter the green beans around, toss in the pan oil, and roast 12–15 minutes (pull the pork at 140°F).","Rest the pork 5 minutes under foil — non-negotiable for juicy slices.","Slice thick, squeeze lemon over everything, and spoon the pan juices on top."],"tip":"Tenderloin is the weeknight roast: 35 minutes start to carved."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('unstuffed_cabbage_skillet', '{"id":"unstuffed_cabbage_skillet","name":"Unstuffed cabbage-roll skillet","emoji":"🍲","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"cabbage","q":0.5},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"paprika","q":4},{"f":"olive_oil","q":15}],"steps":["Brown the turkey in the oil, 5 minutes; add the diced onion and garlic for 3 more.","Stir in the paprika, then the crushed tomatoes.","Pile in the chopped cabbage — it looks like too much; it is not.","Cover and simmer 12 minutes until the cabbage is tender.","Season and serve; all the flavor of cabbage rolls, none of the rolling."],"tip":"Deconstructed classics exist because weeknights do."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_asparagus_skillet', '{"id":"shrimp_asparagus_skillet","name":"Lemon shrimp & asparagus skillet","emoji":"🍋","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["shellfish"],"time":15,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"asparagus","q":340},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"black_pepper","q":1},{"f":"salt","q":3}],"steps":["Snap the asparagus where it wants to break and cut into thirds.","Sear it in half the oil over medium-high, 3–4 minutes, until blistered but snappy; set aside.","Sear the dried, seasoned shrimp in the rest of the oil, 90 seconds per side, adding the garlic at the flip.","Return the asparagus, toss once.","Off heat: lemon zest, lemon juice, and a final glug of oil."],"tip":"Fifteen minutes, one pan, and it looks like you tried much harder."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cottage_cheese_berry_bowl', '{"id":"cottage_cheese_berry_bowl","name":"Whipped cottage cheese & berry bowl","emoji":"🫐","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","nuts"],"time":5,"servings":2,"ing":[{"f":"cottage_cheese","q":400},{"f":"berries","q":200},{"f":"honey","q":15},{"f":"walnuts","q":30},{"f":"cinnamon","q":1}],"steps":["Blitz the cottage cheese 30 seconds until whipped and smooth (or embrace the curds and skip this).","Divide between bowls.","Top with the berries and toasted walnuts.","Drizzle the honey and dust with cinnamon.","That’s it — 25 grams of protein disguised as dessert."],"tip":"Blending is cottage cheese’s redemption arc."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_avocado_lettuce_boats', '{"id":"tuna_avocado_lettuce_boats","name":"Tuna-avocado lettuce boats","emoji":"🛶","cuisine":"American","meal":["lunch"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["fish"],"time":10,"servings":2,"ing":[{"f":"tuna_canned","q":284},{"f":"avocado","q":1},{"f":"romaine","q":1},{"f":"lime","q":1},{"f":"onion","q":0.2},{"f":"cilantro","q":0.2},{"f":"olive_oil","q":10}],"steps":["Mash the avocado with the lime juice and a pinch of salt.","Fold in the drained tuna, minced onion and cilantro — avocado replaces mayo entirely.","Separate the romaine into sturdy leaf-boats.","Fill each boat generously.","Finish with oil, pepper, and eat with your hands."],"tip":"Avocado-as-mayo is the upgrade canned tuna has been waiting for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pasta_e_fagioli', '{"id":"pasta_e_fagioli","name":"Pasta e fagioli","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"white_beans","q":400},{"f":"penne","q":120},{"f":"crushed_tomatoes","q":250},{"f":"carrots","q":100},{"f":"celery","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"olive_oil","q":25},{"f":"parsley","q":0.3}],"steps":["Soften the diced onion, carrot and celery in the oil, 6 minutes; add the garlic and oregano for 1 more.","Add the crushed tomatoes, beans and 2½ cups of water; simmer 10 minutes.","Mash a ladleful of beans against the pot to cream the broth.","Add the pasta straight into the soup and simmer until al dente, 10–11 minutes, stirring so it doesn’t stick.","Rest 5 minutes — it thickens into the proper spoon-standing texture — and finish with parsley and good oil."],"tip":"Cooking the pasta in the soup releases its starch — that is the body of the dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('walnut_pesto_penne', '{"id":"walnut_pesto_penne","name":"Walnut-basil pesto penne","emoji":"🌿","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy","nuts"],"time":20,"servings":2,"ing":[{"f":"penne","q":200},{"f":"basil","q":1},{"f":"walnuts","q":60},{"f":"parmesan","q":50},{"f":"garlic","q":0.1},{"f":"olive_oil","q":50},{"f":"lemon","q":0.5}],"steps":["Toast the walnuts in a dry pan, 3 minutes; cool slightly.","Blitz the basil leaves, walnuts, parmesan, garlic and oil into a rough pesto; season with salt and lemon juice.","Cook the penne; reserve a cup of pasta water.","Toss the pasta with the pesto OFF the heat, loosening with pasta water until it clings.","More parmesan over the top, obviously."],"tip":"Heat kills pesto’s color and perfume — it dresses pasta, it never cooks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_tomato_penne', '{"id":"bacon_tomato_penne","name":"Amatriciana-style bacon & tomato penne","emoji":"🥓","cuisine":"Italian","meal":["dinner"],"diets":[],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"penne","q":200},{"f":"bacon","q":120},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":0.5},{"f":"parmesan","q":40},{"f":"olive_oil","q":10},{"f":"black_pepper","q":2}],"steps":["Render the chopped bacon in the oil over medium until crisp; lift it out, leaving the fat.","Soften the sliced onion in the bacon fat, 4 minutes.","Add the crushed tomatoes and plenty of black pepper; simmer 12 minutes.","Cook the penne; finish it in the sauce with a splash of pasta water and most of the bacon.","Serve with parmesan and the reserved bacon on top."],"tip":"Guanciale is traditional; bacon is Tuesday. Both are delicious."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_kale_soup', '{"id":"white_bean_kale_soup","name":"Tuscan white bean & kale soup","emoji":"🥬","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"white_beans","q":500},{"f":"kale","q":1},{"f":"carrots","q":120},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"olive_oil","q":30},{"f":"lemon","q":0.5}],"steps":["Soften the diced onion and carrots in half the oil, 6 minutes; add the garlic and oregano for 1 minute.","Add the beans and 3 cups of water; simmer 10 minutes.","Blend a third of the pot and stir it back — creamy broth, no cream.","Stir in the stripped, chopped kale; simmer 5 minutes until tender.","Finish with lemon juice and the rest of the oil in slow circles over each bowl."],"tip":"The partial blend is the oldest trick in Tuscany — body without dairy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ricotta_spinach_penne', '{"id":"ricotta_spinach_penne","name":"Creamy ricotta & spinach penne","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"penne","q":200},{"f":"ricotta","q":250},{"f":"spinach","q":150},{"f":"garlic","q":0.2},{"f":"parmesan","q":40},{"f":"lemon","q":0.5},{"f":"olive_oil","q":15},{"f":"black_pepper","q":2}],"steps":["Cook the penne; reserve a big cup of pasta water.","Sizzle the sliced garlic in the oil, then wilt the spinach, 1 minute.","Off heat, stir the ricotta with half the parmesan, lemon zest and a ladle of hot pasta water into a sauce right in the pan.","Fold in the pasta, loosening with more water until silky.","Finish with lemon juice, the rest of the parmesan and aggressive black pepper."],"tip":"Ricotta + pasta water = alfredo energy with a third of the effort."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_chicken_caprese', '{"id":"balsamic_chicken_caprese","name":"Balsamic chicken caprese","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"mozzarella","q":100},{"f":"tomato","q":2},{"f":"basil","q":0.3},{"f":"balsamic_vinegar","q":40},{"f":"olive_oil","q":15},{"f":"garlic","q":0.2}],"steps":["Halve the breasts into cutlets, season, and sear in the oil 3–4 minutes per side.","Add the balsamic and garlic to the pan; let it bubble down to a glaze that coats the chicken, 2 minutes.","Top each cutlet with sliced tomato and mozzarella; cover 2 minutes to melt.","Rest a minute.","Serve painted with the pan glaze and covered in torn basil."],"tip":"Balsamic reduces to candy-glaze in minutes — watch it, it goes from perfect to burnt fast."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('weeknight_minestrone', '{"id":"weeknight_minestrone","name":"Weeknight minestrone","emoji":"🍜","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":4,"ing":[{"f":"white_beans","q":400},{"f":"penne","q":120},{"f":"zucchini","q":1},{"f":"carrots","q":120},{"f":"celery","q":80},{"f":"onion","q":1},{"f":"crushed_tomatoes","q":300},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"olive_oil","q":25},{"f":"parsley","q":0.3}],"steps":["Soften the diced onion, carrot and celery in the oil, 6 minutes.","Add the garlic and oregano, then the crushed tomatoes and 4 cups of water; simmer 10 minutes.","Add the diced zucchini, beans and pasta; simmer until the pasta is just done, 10 minutes.","Season hard — vegetable soups are shy until salted.","Finish with parsley and olive oil; parmesan for the non-vegans at the table."],"tip":"Minestrone is a fridge-clearing format, not a recipe — swap in whatever vegetables are fading."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_ricotta_pancakes', '{"id":"lemon_ricotta_pancakes","name":"Lemon-ricotta pancakes","emoji":"🥞","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["gluten","dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"ricotta","q":250},{"f":"flour","q":120},{"f":"eggs","q":2},{"f":"milk","q":80},{"f":"lemon","q":1},{"f":"maple_syrup","q":60},{"f":"butter","q":15},{"f":"sugar","q":20}],"steps":["Whisk the ricotta, eggs, milk, sugar and the zest of the whole lemon.","Fold in the flour just until combined — lumps are fine, tough pancakes are not.","Cook quarter-cup rounds in butter over medium, 2–3 minutes per side.","They stay custardy in the middle; that is the point, not underdone batter.","Serve with maple syrup and a squeeze of the naked lemon."],"tip":"Ricotta pancakes are what diner pancakes dream of becoming."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_souvlaki_bowls', '{"id":"chicken_souvlaki_bowls","name":"Chicken souvlaki bowls with yogurt sauce","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":1},{"f":"couscous","q":140},{"f":"oregano","q":4},{"f":"lemon","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"tomato","q":1}],"steps":["Marinate the cubed chicken in half the oil, oregano, half the lemon’s juice and half the garlic, 10 minutes.","Stir grated, squeezed cucumber into the yogurt with the rest of the garlic and a pinch of salt — instant tzatziki.","Pour boiling water over the couscous (equal volume), cover 5 minutes, fluff.","Sear the chicken hard on skewers or straight in the pan, 8–10 minutes, until charred at the edges.","Bowl it: couscous, chicken, diced tomato, tzatziki, remaining lemon."],"tip":"Squeeze the grated cucumber like you mean it — watery tzatziki is the only bad tzatziki."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('couscous_tabbouleh', '{"id":"couscous_tabbouleh","name":"Couscous tabbouleh","emoji":"🌿","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":15,"servings":2,"ing":[{"f":"couscous","q":120},{"f":"parsley","q":1},{"f":"tomato","q":2},{"f":"cucumber","q":1},{"f":"scallions","q":0.3},{"f":"lemon","q":1.5},{"f":"olive_oil","q":30}],"steps":["Hydrate the couscous in an equal volume of boiling water, covered, 5 minutes; fluff and cool.","Chop the entire parsley bunch fine — in tabbouleh, parsley is a vegetable, not a garnish.","Dice the tomatoes and cucumber small; slice the scallions.","Toss everything with the lemon juice, oil and a serious pinch of salt.","Rest 10 minutes so the couscous drinks the dressing."],"tip":"The parsley-to-grain ratio should make you slightly nervous. That’s authentic."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_tuna_salad', '{"id":"white_bean_tuna_salad","name":"Italian white bean & tuna salad","emoji":"🐟","cuisine":"Mediterranean","meal":["lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":10,"servings":2,"ing":[{"f":"tuna_canned","q":284},{"f":"white_beans","q":400},{"f":"onion","q":0.2},{"f":"parsley","q":0.4},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"black_pepper","q":2}],"steps":["Rinse and drain the beans; flake in the drained tuna.","Sliver the onion paper-thin and soak it in the lemon juice 5 minutes to tame it.","Chop the parsley roughly.","Fold everything together with the oil, onion and its lemon.","Pepper hard, salt lightly, and let it sit 5 minutes before serving."],"tip":"A Tuscan classic with two cans and one lemon — pantry lunch royalty."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mezze_bowls', '{"id":"mezze_bowls","name":"Mezze plate bowls","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"hummus","q":160},{"f":"feta","q":80},{"f":"olives","q":80},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":200},{"f":"roasted_red_peppers","q":100},{"f":"pita","q":2},{"f":"olive_oil","q":15},{"f":"oregano","q":2}],"steps":["Swoosh the hummus across two wide bowls.","Arrange the halved tomatoes, sliced cucumber, olives, torn roasted peppers and feta in piles.","Warm the pitas and cut into wedges.","Drizzle everything with oil and dust with oregano.","Assemble bites at will — this is legally a cooked dinner."],"tip":"Mezze is the anti-recipe: quality ingredients, zero technique, maximum table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('artichoke_lemon_chicken', '{"id":"artichoke_lemon_chicken","name":"Artichoke-lemon chicken skillet","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"artichoke_hearts","q":240},{"f":"lemon","q":1},{"f":"garlic","q":0.3},{"f":"parsley","q":0.3},{"f":"olive_oil","q":25},{"f":"oregano","q":2}],"steps":["Halve the breasts into cutlets, season with oregano and salt, and sear in the oil 3–4 minutes per side; set aside.","Brown the drained, halved artichokes in the same pan, cut-side down, 3 minutes.","Add the garlic for 30 seconds, then the juice of the lemon and a splash of water, scraping the pan.","Return the chicken to warm through in the sauce, 2 minutes.","Shower with parsley and serve with the pan juices."],"tip":"Canned artichokes brown beautifully if you dry them first — treat them like a vegetable, not a garnish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_baked_white_beans', '{"id":"greek_baked_white_beans","name":"Greek baked white beans (gigantes-style)","emoji":"🫘","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"white_beans","q":500},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"oregano","q":4},{"f":"honey","q":10},{"f":"olive_oil","q":40},{"f":"parsley","q":0.3}],"steps":["Heat the oven to 400°F. Soften the diced onion in half the oil; add the garlic and oregano for 1 minute.","Stir in the crushed tomatoes, honey, beans and a splash of water.","Pour into a baking dish, top with the remaining oil.","Bake 25 minutes until bubbling with caramelized edges.","Rest 10 minutes and finish with parsley — served warm, never hot."],"tip":"The whisper of honey against the tomatoes is the traditional move — sweet-savory, not sweet."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_couscous_bowl', '{"id":"salmon_couscous_bowl","name":"Lemon salmon & couscous bowl","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten"],"time":20,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"couscous","q":140},{"f":"cucumber","q":0.5},{"f":"olives","q":50},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"olive_oil","q":20}],"steps":["Hydrate the couscous in boiling water, covered, 5 minutes; fluff with a fork and half the oil.","Sear the seasoned salmon 4 minutes skin-side, 2 flesh-side; rest and flake.","Dice the cucumber, halve the olives, chop the parsley.","Fold the vegetables and herbs through the couscous with the lemon juice.","Top with the salmon and the last of the oil."],"tip":"Couscous is the five-minute grain — faster than toast, fancier than rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka', '{"id":"shakshuka","name":"Shakshuka","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"crushed_tomatoes","q":400},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"cumin","q":4},{"f":"paprika","q":4},{"f":"feta","q":60},{"f":"olive_oil","q":20},{"f":"parsley","q":0.3}],"steps":["Soften the sliced onion and pepper in the oil over medium, 8 minutes — properly soft, this is the base.","Add the garlic, cumin and paprika for 1 minute, then the crushed tomatoes; simmer 8 minutes until thick.","Nest wells in the sauce and crack an egg into each; season the yolks.","Cover and cook 5–7 minutes until the whites set but the yolks tremble.","Crumble the feta over, add parsley, and serve from the pan with bread for the non-low-carb table."],"tip":"The sauce must be thick before the eggs go in — soup poaches badly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_roasted_veg_couscous', '{"id":"balsamic_roasted_veg_couscous","name":"Balsamic roasted vegetables & couscous","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"zucchini","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"balsamic_vinegar","q":30},{"f":"couscous","q":140},{"f":"olive_oil","q":30},{"f":"oregano","q":3}],"steps":["Heat the oven to 425°F. Chunk all the vegetables evenly.","Toss with the oil, oregano and salt on a sheet pan; roast 25 minutes until charred at the corners.","Drizzle the balsamic over the hot pan and toss — it glazes on contact.","Hydrate the couscous meanwhile.","Pile the glazed vegetables over the couscous, scraping every dark sticky bit from the pan."],"tip":"Balsamic on hot-from-the-oven vegetables becomes a glaze without ever seeing a saucepan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avgolemono_soup', '{"id":"avgolemono_soup","name":"Avgolemono (Greek lemon chicken soup)","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"broth","q":1000},{"f":"rice","q":100},{"f":"eggs","q":2},{"f":"lemon","q":1.5},{"f":"parsley","q":0.2},{"f":"olive_oil","q":10}],"steps":["Simmer the chicken in the broth until cooked, 12 minutes; shred it and return it, adding the rice for 15 minutes.","Whisk the eggs with the juice of the lemons until frothy.","Temper: whisk hot broth into the eggs one ladle at a time — three ladles minimum.","Off the heat, stir the tempered eggs back into the pot; it turns velvety and pale.","Do not boil it again. Season, add parsley, serve."],"tip":"Tempering feels fussy the first time and automatic forever after — silk from two eggs and a lemon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_pork_rice_bowls', '{"id":"ginger_pork_rice_bowls","name":"Ginger-glazed pork rice bowls","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["soy","gluten"],"time":25,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"ginger","q":15},{"f":"soy_sauce","q":35},{"f":"honey","q":20},{"f":"garlic","q":0.3},{"f":"rice","q":160},{"f":"cabbage","q":0.3},{"f":"scallions","q":0.5},{"f":"olive_oil","q":15}],"steps":["Start the rice. Slice the pork thin against the grain.","Sear the pork in the oil over high heat in two batches, 2 minutes each; set aside.","Add the ginger and garlic, then the soy sauce and honey; bubble to a glaze.","Return the pork and toss to coat.","Serve over rice with a pile of thin-shaved raw cabbage and scallions for crunch."],"tip":"Thin slices against the grain make loin taste like a far more expensive cut."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_kale_edamame_salad', '{"id":"sesame_kale_edamame_salad","name":"Sesame kale & edamame crunch salad","emoji":"🥗","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["soy","sesame","nuts","gluten"],"time":15,"servings":2,"ing":[{"f":"kale","q":1},{"f":"edamame_frozen","q":250},{"f":"carrots","q":100},{"f":"cashews","q":40},{"f":"sesame_oil","q":15},{"f":"soy_sauce","q":20},{"f":"honey","q":10},{"f":"lime","q":1},{"f":"ginger","q":8}],"steps":["Blanch the edamame in boiling water 3 minutes; drain and cool.","Massage the stripped, shredded kale with a pinch of salt until it relaxes.","Whisk the sesame oil, soy sauce, honey, lime juice and grated ginger.","Toss the kale, edamame and ribboned carrots with the dressing.","Top with toasted cashews. Keeps dressed for a day — kale does not wilt like lettuce."],"tip":"This is the salad that survives meal prep — day two is arguably better."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_egg_breakfast_tacos', '{"id":"bacon_egg_breakfast_tacos","name":"Bacon & egg breakfast tacos","emoji":"🌮","cuisine":"Mexican","meal":["breakfast"],"diets":[],"allergens":["gluten","eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"eggs","q":4},{"f":"bacon","q":120},{"f":"cheddar","q":50},{"f":"salsa","q":100},{"f":"avocado","q":0.5},{"f":"scallions","q":0.3}],"steps":["Crisp the chopped bacon; pour off all but a slick of the fat.","Scramble the eggs soft in the bacon pan.","Warm the tortillas; slice the avocado.","Fill: cheddar first (it melts under the eggs), then eggs, bacon, avocado.","Salsa and scallions over everything."],"tip":"Cheese under hot eggs is self-melting engineering."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_carnitas_bowls', '{"id":"pork_carnitas_bowls","name":"Carnitas-style pork bowls","emoji":"🍖","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"pork_loin","q":500},{"f":"lime","q":2},{"f":"cumin","q":5},{"f":"oregano","q":3},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"rice","q":160},{"f":"black_beans","q":250},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Cube the pork and toss with cumin, oregano, salt and the juice of one lime.","Brown it hard in the oil, then add the sliced onion, garlic and ½ cup water; cover and simmer 25 minutes until shreddable.","Uncover, crank the heat, and let the liquid cook off so the edges crisp — that contrast is carnitas.","Warm the beans; cook the rice.","Bowl it all with cilantro and the second lime."],"tip":"Braise then crisp: tender inside, crackly edges — the two-texture secret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('masala_green_beans_potatoes', '{"id":"masala_green_beans_potatoes","name":"Masala green beans & potatoes","emoji":"🫛","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"green_beans","q":300},{"f":"potatoes","q":400},{"f":"onion","q":0.5},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"garam_masala","q":3},{"f":"ginger","q":8},{"f":"olive_oil","q":25},{"f":"lemon","q":0.5}],"steps":["Brown the small-diced potatoes in the oil, covered, stirring now and then, 10 minutes.","Add the onion, ginger, turmeric and cumin; 2 minutes.","Add the trimmed, halved green beans and a splash of water; cover 6–8 minutes until just tender.","Uncover and let everything catch a little color.","Finish with garam masala and lemon."],"tip":"A dry sabzi wants a lid early and no lid late — steam, then sizzle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_tikka_masala', '{"id":"chickpea_tikka_masala","name":"Chickpea tikka masala","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":500},{"f":"crushed_tomatoes","q":300},{"f":"coconut_milk","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"garam_masala","q":6},{"f":"paprika","q":4},{"f":"cumin","q":3},{"f":"rice","q":140},{"f":"olive_oil","q":20}],"steps":["Start the rice. Golden the diced onion in the oil, 6 minutes; add garlic, ginger, cumin and paprika for 1 minute.","Add the crushed tomatoes and simmer 8 minutes until darkened and thick — this patience IS tikka masala.","Blend the sauce smooth with the coconut milk (or don’t; rustic is fine).","Add the chickpeas and simmer 8 minutes to marry.","Finish with garam masala; serve over rice."],"tip":"The long tomato reduction is the restaurant secret — thin sauce, thin flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_shrimp_curry', '{"id":"coconut_shrimp_curry","name":"Coconut shrimp curry","emoji":"🍤","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["shellfish"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"coconut_milk","q":250},{"f":"crushed_tomatoes","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"curry_powder","q":10},{"f":"garam_masala","q":3},{"f":"rice","q":140},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15}],"steps":["Start the rice. Golden the diced onion in the oil; bloom the curry powder with the garlic and ginger, 1 minute.","Add the crushed tomatoes; cook 3 minutes.","Pour in the coconut milk and simmer 5 minutes to a light sauce.","Slide in the dried shrimp; 2–3 minutes only, until just pink and curled.","Finish with garam masala and cilantro over rice — the shrimp keep cooking in the hot sauce, so err early."],"tip":"Shrimp curries live or die in a 90-second window — sauce first, shrimp last."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turmeric_khichdi', '{"id":"turmeric_khichdi","name":"Turmeric khichdi (rice & lentil comfort pot)","emoji":"🍚","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"rice","q":120},{"f":"lentils_dry","q":120},{"f":"turmeric","q":4},{"f":"cumin","q":4},{"f":"ginger","q":10},{"f":"carrots","q":100},{"f":"peas_frozen","q":100},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5}],"steps":["Rinse the rice and lentils together until the water runs clearish.","Bloom the cumin and ginger in the oil, 30 seconds; add the turmeric, rice, lentils and diced carrot.","Add 4 cups of water and a big pinch of salt; simmer partially covered 25 minutes, stirring occasionally, until porridgy.","Stir in the peas for the last 3 minutes.","Finish with lemon. Loose and spoonable is correct — it thickens as it sits."],"tip":"Khichdi is what Indian kitchens make when someone needs comfort — rice-and-lentils as a hug."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_lentil_bolognese', '{"id":"mushroom_lentil_bolognese","name":"Mushroom Lentil Bolognese","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":55,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"garlic","q":0.4},{"f":"mushrooms","q":400},{"f":"lentils_dry","q":250},{"f":"crushed_tomatoes","q":800},{"f":"oregano","q":3},{"f":"spaghetti","q":400},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Finely chop the mushrooms, onion, and carrots so they mimic the texture of a classic ragu.","Heat the olive oil in a wide pot over medium-high heat and cook the mushrooms undisturbed for 5 minutes, until their liquid evaporates and they turn deeply browned at the edges.","Stir in the onion, carrots, and garlic and cook 5 minutes more, then add the tomato paste and fry it for 2 minutes until it darkens to brick red and smells sweet.","Add the lentils, crushed tomatoes, 500 milliliters of water, oregano, salt, and pepper, then simmer partially covered for 30 to 35 minutes, until the lentils are tender and the sauce is thick enough to mound on a spoon.","Meanwhile, boil the spaghetti in well-salted water until just shy of al dente, then drag it into the sauce with a splash of pasta water and toss for 1 minute so every strand is coated.","Taste, adjust the salt, and serve in warm bowls with extra black pepper."],"tip":"Brown the mushrooms like you mean it — pale mushrooms make a sauce that tastes like a missed opportunity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_shawarma_bowls', '{"id":"chickpea_shawarma_bowls","name":"Chickpea Shawarma Bowls","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["sesame"],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"olive_oil","q":25},{"f":"cumin","q":4},{"f":"paprika","q":4},{"f":"turmeric","q":2},{"f":"cinnamon","q":1},{"f":"rice","q":130},{"f":"cucumber","q":1},{"f":"tomato","q":1.7},{"f":"onion","q":0.5},{"f":"lemon","q":1},{"f":"hummus","q":100},{"f":"parsley","q":0.2},{"f":"salt","q":4}],"steps":["Heat the oven to 220C (425F) and start the rice simmering in salted water so everything finishes together.","Pat the chickpeas very dry, then toss them with the olive oil, cumin, smoked paprika, turmeric, cinnamon, and salt until every one is stained golden.","Roast the chickpeas on a sheet pan for 20 to 25 minutes, shaking the pan halfway, until they are crisp outside and creamy inside.","While they roast, dice the cucumber and tomatoes, slice the red onion into thin half-moons, and toss the lot with half the lemon''s juice and a pinch of salt.","Pile the rice into two bowls, top with hot chickpeas and the cool salad, then finish with generous swoops of hummus, chopped parsley, and the remaining lemon squeezed over everything.","Eat immediately, while the chickpeas still crackle."],"tip":"Dry chickpeas roast crisp and wet chickpeas steam sad — a clean kitchen towel is your shawarma insurance policy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_curry_tofu', '{"id":"coconut_curry_tofu","name":"Coconut Curry Tofu","emoji":"🍛","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":["soy"],"time":45,"servings":2,"ing":[{"f":"tofu","q":450},{"f":"coconut_milk","q":250},{"f":"curry_powder","q":8},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"broccoli","q":250},{"f":"rice","q":140},{"f":"lime","q":1},{"f":"maple_syrup","q":10},{"f":"olive_oil","q":15},{"f":"salt","q":5}],"steps":["Press the tofu for 10 minutes, cut it into 2-centimeter cubes, and get the rice cooking in salted water.","Sear the tofu in the oil in a hot nonstick skillet for 8 to 10 minutes, turning occasionally, until golden and crusty on most sides, then set it aside.","In the same pan, soften the sliced onion and bell pepper for 4 minutes, then add the grated ginger, minced garlic, and curry powder and stir for 60 seconds until intensely fragrant.","Pour in the coconut milk with a splash of water, add the broccoli, maple syrup, and salt, and simmer for 6 to 8 minutes until the broccoli is bright and just tender and the sauce coats a spoon.","Return the tofu to the pan, simmer 2 minutes so it drinks up the sauce, and finish with a big squeeze of lime.","Serve over the rice with more lime on the side."],"tip":"Resist stirring the tofu while it sears — it releases from the pan on its own schedule, like a cat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('black_bean_sweet_potato_hash', '{"id":"black_bean_sweet_potato_hash","name":"Black Bean Sweet Potato Hash","emoji":"🍳","cuisine":"American","meal":["breakfast","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":400},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":25},{"f":"paprika","q":4},{"f":"cumin","q":3},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":5}],"steps":["Dice the sweet potatoes into 1-centimeter cubes so they cook through before they burn.","Heat the oil in your largest skillet over medium heat, add the sweet potatoes with a pinch of salt, and cook covered for 8 minutes, stirring once, until nearly tender.","Uncover, raise the heat to medium-high, and add the diced onion and bell pepper, cooking 6 to 8 minutes more until the potatoes are browned and crisp-edged.","Stir in the drained black beans, smoked paprika, and cumin and cook 3 minutes, pressing the hash flat against the pan so the bottom crackles and caramelizes.","Kill the heat, squeeze the lime over the top, and shower with cilantro.","Serve topped with sliced avocado and an extra pinch of salt on the avocado itself."],"tip":"The lid is a shortcut, not a lifestyle — take it off in time for the crispy bits, which are the whole point of hash."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_tikka_bowls', '{"id":"cauliflower_tikka_bowls","name":"Cauliflower Tikka Bowls","emoji":"🥘","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"chickpeas","q":240},{"f":"coconut_milk","q":200},{"f":"crushed_tomatoes","q":250},{"f":"garam_masala","q":6},{"f":"turmeric","q":2},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"onion","q":1},{"f":"olive_oil","q":25},{"f":"rice","q":140},{"f":"cilantro","q":0.3},{"f":"lemon","q":0.5},{"f":"salt","q":5}],"steps":["Heat the oven to 230C (450F), toss the cauliflower florets with half the oil, half the garam masala, the turmeric, and a pinch of salt, and roast for 22 to 25 minutes until charred at the tips.","Meanwhile, cook the rice and soften the diced onion in the remaining oil over medium heat for 5 minutes, until translucent and sweet.","Add the grated ginger, minced garlic, and remaining garam masala and fry for 60 seconds, then pour in the crushed tomatoes and simmer 8 minutes until the sauce darkens and thickens.","Stir in the coconut milk and chickpeas and simmer gently for 5 minutes more, until the sauce is silky and coats the back of a spoon.","Fold the roasted cauliflower into the sauce, letting the charred edges soak up the gravy for a minute or two.","Serve over rice with cilantro and a squeeze of lemon to wake everything up."],"tip":"Char is flavor — if your cauliflower looks a little too brave at the edges, it is exactly right."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('edamame_avocado_rice_bowls', '{"id":"edamame_avocado_rice_bowls","name":"Edamame Avocado Rice Bowls","emoji":"🥑","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"rice","q":160},{"f":"edamame_frozen","q":300},{"f":"avocado","q":1.5},{"f":"cucumber","q":1},{"f":"carrots","q":100},{"f":"scallions","q":3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"maple_syrup","q":5},{"f":"ginger","q":10},{"f":"lime","q":1}],"steps":["Cook the rice, and while it steams, whisk the soy sauce, sesame oil, maple syrup, grated ginger, and the juice of half the lime into a glossy dressing.","Boil the edamame in salted water for 4 minutes, until bright green and just tender, then drain well.","Slice the cucumber into thin coins, shave the carrots into ribbons with a vegetable peeler, and slice the scallions on a sharp angle.","Fluff the hot rice and divide it between two bowls, then arrange the edamame, cucumber, carrots, and fanned avocado slices in neat sections on top.","Spoon the dressing over everything, scatter with scallions, and finish with the remaining lime squeezed at the table."],"tip":"Dress the bowl right before eating — soy sauce turns cucumber into a water feature if you let it sit."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_spiced_chickpea_stew', '{"id":"moroccan_spiced_chickpea_stew","name":"Moroccan Spiced Chickpea Stew","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"cumin","q":6},{"f":"cinnamon","q":2},{"f":"paprika","q":5},{"f":"crushed_tomatoes","q":800},{"f":"chickpeas","q":720},{"f":"sweet_potatoes","q":400},{"f":"spinach","q":150},{"f":"lemon","q":1},{"f":"maple_syrup","q":10},{"f":"salt","q":8}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion with a pinch of salt for 6 to 8 minutes, until soft and golden at the edges.","Add the minced garlic, grated ginger, cumin, cinnamon, and smoked paprika and stir constantly for 60 seconds, until the spices bloom and the kitchen smells like a souk.","Pour in the crushed tomatoes, 750 milliliters of water, the maple syrup, chickpeas, and the sweet potatoes cut into 2-centimeter chunks, then bring to a lively simmer.","Cook uncovered for 25 to 30 minutes, stirring occasionally, until the sweet potatoes are fork-tender and the stew has thickened enough to leave a trail when you drag a spoon through it.","Stir in the spinach in handfuls until it wilts, then season with salt and the juice of the lemon.","Ladle into deep bowls and let it sit 5 minutes before serving — it thickens and improves as it rests."],"tip":"This stew is even better on day two, so consider dinner tonight merely a quality-control check."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('grilled_veggie_hummus_wraps', '{"id":"grilled_veggie_hummus_wraps","name":"Grilled Veggie Hummus Wraps","emoji":"🌯","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tortillas","q":2},{"f":"hummus","q":150},{"f":"zucchini","q":1.5},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":20},{"f":"spinach","q":60},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"salt","q":4}],"steps":["Slice the zucchini lengthwise into half-centimeter planks, cut the bell pepper into wide flat pieces, and slice the red onion into thick rings.","Toss the vegetables with olive oil, oregano, and salt, then grill them in a screaming-hot grill pan for 3 to 4 minutes per side, until deeply striped and tender but not mushy.","Hit the hot vegetables with a squeeze of lemon the moment they come off the heat so they drink it in.","Warm the tortillas for 20 seconds per side in the same pan, then spread each one edge-to-edge with a thick layer of hummus.","Layer on the spinach and grilled vegetables in a tight log down the center, then fold in the sides and roll firmly away from you.","Return each wrap to the pan seam-side down for a minute to seal and crisp before slicing on the diagonal."],"tip":"Hummus is both sauce and glue here — spread it to the edges or your wrap will unravel at the first ambitious bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cold_peanut_noodle_salad', '{"id":"cold_peanut_noodle_salad","name":"Cold Peanut Noodle Salad","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"rice_noodles","q":180},{"f":"peanut_butter","q":80},{"f":"soy_sauce","q":30},{"f":"lime","q":1},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"cabbage","q":0.2},{"f":"carrots","q":150},{"f":"cucumber","q":0.8},{"f":"scallions","q":3},{"f":"cilantro","q":0.3}],"steps":["Cook the rice noodles according to the package until just tender, then rinse them under cold water until completely cool and drain well.","Whisk the peanut butter, soy sauce, lime juice, maple syrup, sesame oil, grated ginger, and minced garlic with 3 to 4 tablespoons of warm water until the sauce is smooth and pourable, like heavy cream.","Shred the cabbage finely, cut the carrots and cucumber into thin matchsticks, and slice the scallions.","Toss the noodles and vegetables with the sauce in your biggest bowl, using tongs and some enthusiasm, until every strand is slicked.","Chill for 10 minutes if you can bear it, then top with cilantro and extra lime wedges and serve cold."],"tip":"Peanut sauce thickens as it sits, so keep a splash of water handy to loosen leftovers back to their former glory."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_ratatouille_bake', '{"id":"white_bean_ratatouille_bake","name":"White Bean Ratatouille Bake","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":65,"servings":4,"ing":[{"f":"eggplant","q":0.9},{"f":"zucchini","q":2},{"f":"bell_pepper","q":2},{"f":"tomato","q":3.3},{"f":"crushed_tomatoes","q":400},{"f":"white_beans","q":800},{"f":"olive_oil","q":60},{"f":"garlic","q":0.5},{"f":"onion","q":1},{"f":"oregano","q":3},{"f":"parsley","q":0.3},{"f":"salt","q":8}],"steps":["Heat the oven to 200C (400F) and cut the eggplant, zucchini, bell peppers, and fresh tomatoes into chunky 2-centimeter pieces.","In a large baking dish, stir together the crushed tomatoes, drained white beans, sliced garlic, diced onion, half the olive oil, oregano, red pepper flakes, and salt to make the saucy base.","Tumble the cut vegetables over the top, drizzle with the remaining oil, and season generously — eggplant is a salt sponge and rewards courage.","Bake uncovered for 45 to 50 minutes, stirring once at the halfway mark, until the vegetables are collapsed and jammy and the edges of the dish are bubbling and browned.","Rest the bake for 10 minutes out of the oven so the juices settle from soup back into sauce.","Shower with parsley and serve warm, in shallow bowls, with the crusty corner bits distributed fairly."],"tip":"Ratatouille punishes impatience — undercooked eggplant is squeaky, so give it the full bake and then some."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('taco_spiced_lentil_bowls', '{"id":"taco_spiced_lentil_bowls","name":"Taco Spiced Lentil Bowls","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"lentils_dry","q":200},{"f":"chili_powder","q":8},{"f":"cumin","q":5},{"f":"paprika","q":4},{"f":"garlic","q":0.3},{"f":"onion","q":1},{"f":"olive_oil","q":15},{"f":"rice","q":100},{"f":"corn_frozen","q":120},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":5}],"steps":["Start the rice in salted water, then heat the oil in a saucepan and cook the diced onion over medium heat for 5 minutes until softened and lightly golden.","Add the minced garlic, chili powder, cumin, and smoked paprika and toast for 45 seconds, then stir in the tomato paste and fry until it deepens in color.","Add the rinsed lentils and 600 milliliters of water, bring to a boil, then simmer uncovered for 22 to 25 minutes, until the lentils are tender and the mixture is thick and saucy like taco filling.","Stir the corn into the lentils for the last 3 minutes and season assertively with salt and half the lime''s juice.","Build the bowls with rice on the bottom, a generous ladle of taco lentils, sliced avocado, cilantro, and the remaining lime in wedges.","Taste one spoonful before serving and ask yourself if it needs more lime — it usually does."],"tip":"Toasting the spices in oil for under a minute does more for flavor than doubling them ever could."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('kale_white_bean_garlic_penne', '{"id":"kale_white_bean_garlic_penne","name":"Kale and White Bean Garlic Penne","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"penne","q":200},{"f":"white_beans","q":400},{"f":"kale","q":1},{"f":"garlic","q":0.6},{"f":"olive_oil","q":40},{"f":"lemon","q":1},{"f":"salt","q":6}],"steps":["Boil the penne in aggressively salted water until 2 minutes shy of al dente, reserving a cup of the starchy water before draining.","Meanwhile, warm the olive oil in a large skillet over medium-low heat and cook the thinly sliced garlic for 2 to 3 minutes, until pale gold and fragrant — pull it before it browns and turns bitter.","Add the red pepper flakes, then the stemmed and torn kale with a good splash of water, and cook 4 minutes until the kale is silky and deep green.","Stir in the drained white beans, mashing about a third of them against the pan to create a creamy base.","Add the penne with a splash of pasta water and toss vigorously over medium heat for 2 minutes, until the starchy liquid tightens into a sauce that clings to the tubes.","Finish with lemon zest and juice, taste for salt, and serve straight from the pan."],"tip":"The mashed beans are doing the parmesan''s old job here — no one at the table needs to know."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_walnut_baked_oatmeal', '{"id":"maple_walnut_baked_oatmeal","name":"Maple Walnut Baked Oatmeal","emoji":"🥣","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":50,"servings":4,"ing":[{"f":"oats","q":300},{"f":"walnuts","q":100},{"f":"maple_syrup","q":90},{"f":"banana","q":2},{"f":"coconut_milk","q":250},{"f":"cinnamon","q":4},{"f":"salt","q":2},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 190C (375F) and lightly oil a 20-centimeter baking dish.","Mash the bananas to a smooth puree in a large bowl, then whisk in the coconut milk, most of the maple syrup, the cinnamon, and the salt along with 250 milliliters of water.","Stir in the oats and half the walnuts, roughly chopped, then pour the mixture into the dish and let it sit 5 minutes so the oats begin to drink.","Scatter the remaining walnuts over the top and drizzle with the last of the maple syrup for a glossy, candied crust.","Bake for 35 to 40 minutes, until the center is just set and springs back lightly and the walnuts smell toasted.","Cool for 10 minutes before cutting into squares — it firms up dramatically as it rests."],"tip":"Bake it Sunday and you have breakfast until Thursday; a square reheats beautifully and even tolerates being eaten cold over the sink."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('carrot_ginger_soup', '{"id":"carrot_ginger_soup","name":"Silky Carrot-Ginger Soup","emoji":"🥕","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"carrots","q":500},{"f":"onion","q":1},{"f":"ginger","q":25},{"f":"garlic","q":0.2},{"f":"olive_oil","q":30},{"f":"coconut_milk","q":200},{"f":"chickpeas","q":200},{"f":"maple_syrup","q":15}],"steps":["Warm the olive oil in a heavy pot over medium heat, then sweat the chopped onion with a pinch of salt for 5 minutes until translucent but not browned.","Stir in the sliced carrots, grated ginger, and minced garlic and cook 3 minutes more, until the ginger smells sharp and bright.","Pour in 750 ml of water and the maple syrup, add the chickpeas, and simmer uncovered for 20 minutes, until a carrot coin smashes easily against the side of the pot.","Add the coconut milk, then blend the soup in batches (or with an immersion blender) until completely silky, at least a full minute per batch.","Return to the pot, season with salt and black pepper, and reheat gently without boiling; serve with a swirl of the reserved coconut cream on top."],"tip":"Blend longer than feels reasonable — the difference between good and restaurant-silky is about 60 extra seconds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tomato_white_bean_basil_soup', '{"id":"tomato_white_bean_basil_soup","name":"Tomato, White Bean & Basil Soup","emoji":"🍅","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":4,"ing":[{"f":"olive_oil","q":60},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":800},{"f":"white_beans","q":480},{"f":"basil","q":0.5},{"f":"maple_syrup","q":10}],"steps":["Heat the olive oil in a Dutch oven over medium heat and cook the diced onion with a generous pinch of salt for 6 to 8 minutes, until soft and just golden at the edges.","Add the minced garlic and cook 60 seconds, until fragrant but not browned, then pour in the crushed tomatoes, 1 liter of water, and the maple syrup.","Bring to a simmer, add the drained beans, and cook uncovered for 15 minutes so the tomatoes lose their raw tang and the broth thickens slightly.","Ladle a third of the soup into a blender, puree until smooth, and stir it back in — this gives you body while keeping whole beans for texture.","Off the heat, tear in the basil leaves, season assertively with salt and pepper, and let it rest 5 minutes before serving so the basil perfumes the whole pot."],"tip":"Add the basil off the heat, always — boiled basil tastes like regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garden_vegetable_rice_soup', '{"id":"garden_vegetable_rice_soup","name":"Garden Vegetable Rice Soup","emoji":"🍲","cuisine":"American","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"carrots","q":200},{"f":"celery","q":150},{"f":"garlic","q":0.3},{"f":"zucchini","q":1},{"f":"peas_frozen","q":150},{"f":"crushed_tomatoes","q":400},{"f":"rice","q":200},{"f":"spinach","q":100}],"steps":["Heat the olive oil in a large pot over medium heat and cook the diced onion, carrot, and celery with a pinch of salt for 8 minutes, stirring occasionally, until the onion turns translucent.","Stir in the garlic and rice and toast for 2 minutes, until the grains look chalky and smell faintly nutty.","Add the crushed tomatoes and 1.5 liters of water, bring to a boil, then reduce to a steady simmer and cook 15 minutes with the lid ajar.","Add the zucchini and peas and simmer 8 to 10 minutes more, until the rice is tender and the zucchini yields to a spoon but still holds its shape.","Turn off the heat, stir in the spinach until it wilts, and season with salt and plenty of black pepper before ladling into bowls."],"tip":"The rice keeps drinking broth as leftovers sit, so stash a cup of extra water or broth to loosen tomorrow''s lunch."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_veggie_breakfast_burritos', '{"id":"tofu_veggie_breakfast_burritos","name":"Tofu Scramble Breakfast Burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","soy"],"time":30,"servings":2,"ing":[{"f":"tofu","q":350},{"f":"tortillas","q":4},{"f":"black_beans","q":150},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.5},{"f":"avocado","q":1},{"f":"salsa","q":120},{"f":"spinach","q":60},{"f":"olive_oil","q":15}],"steps":["Press the tofu between paper towels for 10 minutes, then crumble it into rough, egg-sized curds with your hands.","Heat the olive oil in a wide skillet over medium-high heat and saute the diced onion and bell pepper for 5 minutes, until the pepper blisters at the edges.","Add the crumbled tofu and a big pinch of salt (plus turmeric and cumin if your pantry allows) and cook 6 to 8 minutes, stirring only occasionally so the tofu picks up golden patches.","Fold in the black beans and spinach and cook 2 minutes, just until the spinach collapses and the beans are warmed through.","Warm the tortillas directly over a burner flame or in a dry pan for 20 seconds a side, then load each with scramble, sliced avocado, and salsa.","Fold in the sides, roll tightly away from you, and sear the burritos seam-side down for 1 minute to weld them shut."],"tip":"That final seam-side sear is non-negotiable — it is the difference between a burrito and a lap full of filling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_cinnamon_quinoa_porridge', '{"id":"maple_cinnamon_quinoa_porridge","name":"Maple-Cinnamon Quinoa Porridge","emoji":"🥣","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":25,"servings":2,"ing":[{"f":"quinoa","q":150},{"f":"coconut_milk","q":200},{"f":"maple_syrup","q":45},{"f":"cinnamon","q":3},{"f":"banana","q":1},{"f":"walnuts","q":30}],"steps":["Rinse the quinoa in a fine-mesh sieve for 30 seconds to wash off its bitter coating, then drain well.","Combine the quinoa with 350 ml of water and a pinch of salt in a saucepan, bring to a boil, then cover and simmer on low for 12 minutes, until the grains show their little spiral tails.","Stir in the coconut milk, cinnamon, and maple syrup and simmer uncovered for 3 to 4 minutes, stirring, until the porridge is creamy and coats a spoon.","Meanwhile, toast the walnuts in a dry skillet over medium heat for 3 minutes, tossing often, until fragrant and a shade darker.","Divide the porridge between bowls and top with sliced banana, toasted walnuts, and an extra thread of maple syrup."],"tip":"Do not skip the rinse — unwashed quinoa carries a soapy bitterness that no amount of maple can bribe away."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_butter_overnight_oats', '{"id":"peanut_butter_overnight_oats","name":"Peanut Butter Overnight Oats","emoji":"🥜","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":10,"servings":2,"ing":[{"f":"oats","q":120},{"f":"peanut_butter","q":60},{"f":"maple_syrup","q":30},{"f":"coconut_milk","q":250},{"f":"banana","q":1}],"steps":["Whisk the peanut butter, maple syrup, and a pinch of salt into the coconut milk in a bowl until no streaks remain — do this first, because peanut butter refuses to blend once the oats are in.","Stir in the oats until every flake is submerged and glossy.","Divide between two jars, press the surface flat with a spoon, and seal the lids.","Refrigerate at least 6 hours or overnight, until the oats are plump and the mixture is thick enough to hold a spoon upright for a beat.","In the morning, stir well, loosen with a splash of water if needed, and crown each jar with sliced banana."],"tip":"Slice the banana in the morning, not the night before, unless brown mush is your love language."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avocado_chickpea_salad_sandwich', '{"id":"avocado_chickpea_salad_sandwich","name":"Smashed Avocado-Chickpea Salad Sandwich","emoji":"🥪","cuisine":"American","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"chickpeas","q":240},{"f":"avocado","q":1},{"f":"onion","q":0.3},{"f":"celery","q":60},{"f":"lemon","q":0.5},{"f":"tomato","q":1},{"f":"romaine","q":0.3},{"f":"olive_oil","q":15}],"steps":["Drain the chickpeas and tip them into a wide bowl with the avocado flesh, then mash with a fork until mostly crushed but still craggy — you want texture, not paste.","Fold in the finely diced red onion and celery, the olive oil, the juice of the half lemon, and a firm seasoning of salt and black pepper.","Taste and adjust: it should be bright enough to make you blink slightly, since bread mutes everything.","Toast the bread until golden and sturdy, then layer lettuce and tomato slices on two pieces.","Pile the chickpea salad high, cap with the remaining toast, press gently, and slice on the diagonal because it genuinely tastes better that way."],"tip":"The lemon juice is doing double duty as seasoning and avocado-browning bodyguard, so be generous."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_tacos', '{"id":"crispy_tofu_tacos","name":"Crispy Tofu Tacos with Lime Slaw","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten","soy"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"tortillas","q":4},{"f":"cabbage","q":0.2},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"salsa","q":100},{"f":"olive_oil","q":30}],"steps":["Press the tofu for 15 minutes under a heavy skillet, then tear it into rough bite-sized chunks — ragged edges crisp better than clean cubes.","Toss the tofu with the cornstarch, a big pinch of salt, and smoked paprika and cumin if you have them, until every piece wears a thin dusty coat.","Heat the olive oil in a nonstick skillet over medium-high until shimmering, then fry the tofu in a single layer for 8 to 10 minutes, turning only when each side releases easily and is deeply golden.","While the tofu fries, toss the shredded cabbage with the juice of half the lime and a pinch of salt, squeezing it with your hands until it just softens.","Char the tortillas over a flame or in a dry pan for 20 seconds per side, then build each taco with slaw, crispy tofu, salsa, and sliced avocado.","Finish with the remaining lime cut into wedges for squeezing at the table."],"tip":"Tear the tofu instead of cubing it — those craggy edges are where the crunch lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_sour_eggplant_caponata', '{"id":"sweet_sour_eggplant_caponata","name":"Sweet & Sour Eggplant Caponata","emoji":"🍆","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"eggplant","q":1.3},{"f":"olive_oil","q":60},{"f":"onion","q":1},{"f":"celery","q":100},{"f":"crushed_tomatoes","q":300},{"f":"olives","q":60},{"f":"balsamic_vinegar","q":45},{"f":"maple_syrup","q":20},{"f":"chickpeas","q":200}],"steps":["Cut the eggplant into 3 cm cubes, salt them, and let them sit in a colander for 15 minutes before patting dry — dry eggplant browns; wet eggplant steams.","Heat two-thirds of the olive oil in a wide skillet over medium-high and fry the eggplant in two batches for 6 to 8 minutes each, until deeply bronzed on several sides, then set aside.","Add the remaining oil and cook the diced onion and celery for 5 minutes, until softened but still with a little bite.","Stir in the crushed tomatoes, olives, raisins, vinegar, maple syrup, and chickpeas and simmer 10 minutes, until the sauce turns thick and jammy.","Return the eggplant to the pan, fold gently so the cubes stay intact, and simmer 5 minutes more so everything trades flavors.","Rest off the heat for at least 15 minutes and serve warm or at room temperature, when the sweet-sour balance is at its loudest."],"tip":"Caponata is one of those rare dishes that is genuinely better tomorrow, so consider making it yesterday."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('savory_mushroom_spinach_oatmeal', '{"id":"savory_mushroom_spinach_oatmeal","name":"Savory Mushroom & Spinach Oatmeal","emoji":"🍄","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy"],"time":25,"servings":2,"ing":[{"f":"oats","q":120},{"f":"mushrooms","q":250},{"f":"spinach","q":100},{"f":"garlic","q":0.2},{"f":"olive_oil","q":30},{"f":"soy_sauce","q":15},{"f":"avocado","q":1}],"steps":["Heat the olive oil in a saucepan over medium-high heat and sear the sliced mushrooms undisturbed for 4 minutes, then stir and cook 3 more, until browned and squeaky-free.","Add the minced garlic and cook 30 seconds, then splash in the soy sauce and let it sizzle and glaze the mushrooms.","Scoop out half the mushrooms for topping, then add the oats to the pan and toast for 1 minute, stirring to coat them in the pan drippings.","Pour in 600 ml of water, bring to a simmer, and cook 8 to 10 minutes, stirring now and then, until the oats are creamy and porridge-like.","Stir in the spinach until the greens wilt, then season with black pepper.","Serve topped with the reserved mushrooms and sliced avocado."],"tip":"Oatmeal is just risotto with better PR — treat it with the same respect and stir near the end for maximum creaminess."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_chickpea_spinach_saute', '{"id":"spanish_chickpea_spinach_saute","name":"Spanish Chickpea & Spinach Saute","emoji":"🫘","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","high-protein"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"chickpeas","q":480},{"f":"spinach","q":300},{"f":"olive_oil","q":45},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"paprika","q":5},{"f":"crushed_tomatoes","q":200},{"f":"lemon","q":0.5}],"steps":["Warm the olive oil in a large skillet over medium heat and cook the diced onion for 5 minutes, until soft and turning gold at the edges.","Add the sliced garlic and cook 90 seconds, until it just begins to color, then pull the pan off the heat and stir in the smoked paprika so it blooms without scorching.","Return to the heat, add the crushed tomatoes and raisins, and simmer 5 minutes until the mixture thickens into a rusty, fragrant sofrito.","Tip in the drained chickpeas and cook 5 minutes, crushing a handful against the pan with your spoon to thicken the sauce.","Add the spinach in big handfuls, folding until each addition collapses, then season with salt and finish with a hard squeeze of lemon.","Serve straight from the skillet while the chickpeas are still glistening."],"tip":"Paprika burns in seconds and turns bitter — blooming it off the heat is the cheapest insurance in Spanish cooking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_corn_black_bean_salad', '{"id":"charred_corn_black_bean_salad","name":"Charred Corn & Black Bean Salad","emoji":"🌽","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"corn_frozen","q":300},{"f":"black_beans","q":400},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.4},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":30},{"f":"cilantro","q":0.3}],"steps":["Heat a dry cast-iron skillet over high heat until it just starts to smoke, then add the corn in a single layer and let it sit untouched for 3 minutes, until blackened in spots.","Toss and char 3 to 4 minutes more, until about a third of the kernels wear dark freckles, then tip into a large bowl to cool slightly.","Add the drained black beans, diced bell pepper, and finely sliced red onion to the warm corn.","Whisk the olive oil with the juice of the whole lime, a pinch of cumin if you like, and a serious pinch of salt, then pour it over and toss.","Fold in the chopped cilantro and diced avocado last, gently, so the avocado stays in cubes rather than becoming dressing.","Let the salad sit 10 minutes before serving — the beans need a moment to soak up the lime."],"tip":"Resist stirring the corn early; char is just patience wearing a smoky disguise."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_carrot_hummus_bowls', '{"id":"roasted_carrot_hummus_bowls","name":"Roasted Carrot & Hummus Grain Bowls","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["sesame"],"time":45,"servings":2,"ing":[{"f":"carrots","q":400},{"f":"hummus","q":200},{"f":"quinoa","q":140},{"f":"chickpeas","q":150},{"f":"olive_oil","q":30},{"f":"cucumber","q":0.8},{"f":"spinach","q":80},{"f":"lemon","q":0.5}],"steps":["Heat the oven to 220C (425F) and cut the carrots into long diagonal batons of even thickness so they roast at the same pace.","Toss the carrots and drained chickpeas with most of the olive oil, salt, and cumin if you have it, spread on a sheet pan without crowding, and roast 25 to 30 minutes, flipping once, until the carrots are caramelized at the tips and the chickpeas rattle when you shake the pan.","Meanwhile, rinse the quinoa, simmer it covered in 330 ml of salted water for 12 minutes, then rest it off the heat 5 minutes and fluff with a fork.","Swipe a thick crescent of hummus around one side of each bowl like you mean it, then pile in the quinoa, spinach, and diced cucumber.","Top with the roasted carrots and crispy chickpeas, drizzle with the remaining olive oil, and finish with a squeeze of lemon and black pepper over everything."],"tip":"Crowded sheet pans steam instead of roast — give the carrots personal space and they will reward you with caramel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_pesto_zoodles', '{"id":"chicken_pesto_zoodles","name":"Chicken Pesto Zoodles with Walnut-Basil Pesto","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"zucchini","q":3},{"f":"basil","q":1},{"f":"walnuts","q":40},{"f":"parmesan","q":30},{"f":"olive_oil","q":40},{"f":"garlic","q":0.2},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Toast the walnuts in a dry skillet over medium heat for 3 to 4 minutes until fragrant, then blitz them with the basil leaves, garlic, parmesan, a squeeze of lemon, and 30 ml of the olive oil until you have a coarse, spoonable pesto; season with salt and pepper.","Slice the chicken breasts in half horizontally, pat dry, and season generously with salt and pepper.","Heat the remaining oil in a large skillet over medium-high and sear the chicken 4 to 5 minutes per side until deeply golden and cooked through, then rest it on a board for 5 minutes before slicing.","Spiralize or julienne the zucchini into noodles, then toss them in the still-hot skillet for just 60 to 90 seconds until barely tender but still snappy.","Pull the pan off the heat, fold in the pesto and sliced chicken, and toss until everything is glossy and green.","Finish with an extra grating of parmesan and a last squeeze of lemon."],"tip":"Zoodles go from al dente to swamp in about two minutes, so treat the skillet like a hot potato and get out fast."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_butter_salmon_green_beans', '{"id":"garlic_butter_salmon_green_beans","name":"Garlic Butter Salmon with Blistered Green Beans","emoji":"🐟","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"green_beans","q":400},{"f":"butter","q":40},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"olive_oil","q":15},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Pat the salmon fillets bone-dry with paper towels and season both sides with salt and pepper; a dry fillet is the whole secret to crisp skin.","Heat the olive oil in a large skillet over medium-high until it shimmers, lay the salmon in skin-side down, and press gently for 10 seconds so the skin stays flat; cook undisturbed for 5 to 6 minutes until the sides turn opaque halfway up.","Flip the fillets, add the butter and minced garlic, and baste the fish with the foaming butter for 2 minutes until it flakes at the thickest point, then move the salmon to warm plates.","Toss the green beans into the same garlicky butter and cook over high heat for 4 to 5 minutes until blistered in spots but still crisp-tender.","Squeeze in the juice of half the lemon, scrape up the browned bits, and season the beans with salt and pepper.","Plate the beans beside the salmon, spoon over the pan butter, and shower with chopped parsley and the remaining lemon in wedges."],"tip":"If the salmon skin sticks, it is not ready to flip — the fish will politely release itself when the crust is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lc_stuffed_pepper_skillet', '{"id":"lc_stuffed_pepper_skillet","name":"Low-Carb Stuffed Pepper Skillet with Cauliflower Rice","emoji":"🫑","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"cauliflower","q":0.5},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":200},{"f":"cheddar","q":60},{"f":"olive_oil","q":15},{"f":"cumin","q":3},{"f":"paprika","q":4},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Pulse the cauliflower florets in a food processor until they look like rice, or grate them on the coarse side of a box grater; set aside.","Heat the olive oil in a large skillet over medium-high, brown the ground beef for 5 to 6 minutes, breaking it into crumbles, and spoon off all but a slick of fat.","Add the diced onion and bell peppers and cook 5 minutes until the peppers soften at the edges, then stir in the garlic, cumin, paprika, and oregano for 30 seconds until fragrant.","Pour in the crushed tomatoes, fold in the cauliflower rice, season with salt and pepper, and simmer for 6 to 8 minutes until the cauliflower is tender and the mixture has thickened enough to mound on a spoon.","Scatter the cheddar over the top, cover, and cook 2 minutes until melted and bubbling.","Let the skillet rest off the heat for a few minutes so the flavors settle, then serve straight from the pan."],"tip":"All the flavor of stuffed peppers with none of the architectural engineering — nobody misses standing them upright."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_pork_medallions_cabbage', '{"id":"balsamic_pork_medallions_cabbage","name":"Balsamic Pork Medallions with Buttered Cabbage","emoji":"🥩","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"cabbage","q":0.5},{"f":"balsamic_vinegar","q":45},{"f":"olive_oil","q":30},{"f":"butter","q":20},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"broth","q":100},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Slice the pork loin into 2.5 cm medallions, flatten each slightly with the heel of your hand, and season well with salt and pepper.","Heat half the olive oil in a wide skillet over medium-high and sear the medallions 3 minutes per side until mahogany-brown and just cooked through, then move them to a plate to rest.","Add the remaining oil, the butter, sliced onion, and thinly shredded cabbage to the pan and cook 8 to 10 minutes, stirring occasionally, until the cabbage collapses and picks up golden edges.","Stir in the garlic for 30 seconds, then push the cabbage aside and pour the balsamic and broth into the pan, scraping up every browned bit.","Simmer 2 to 3 minutes until the liquid turns syrupy enough to coat a spoon, then return the medallions and their juices to glaze in the sauce for a final minute.","Serve the pork on a bed of cabbage with the balsamic pan sauce spooned over."],"tip":"Pork loin punishes overcooking, so pull it when it still has the faintest blush — carryover heat finishes the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_fajita_lettuce_cups', '{"id":"chicken_fajita_lettuce_cups","name":"Chicken Fajita Lettuce Cups","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":30},{"f":"cumin","q":4},{"f":"chili_powder","q":6},{"f":"paprika","q":3},{"f":"salt","q":3}],"steps":["Slice the chicken breasts into finger-width strips and toss them with half the olive oil, the cumin, chili powder, paprika, salt, and the juice of half the lime; let them sit while you prep the vegetables.","Slice the bell peppers and onion into thin strips, and separate, wash, and dry the sturdiest romaine leaves to use as cups.","Get a large skillet screaming hot with the remaining oil and sear the chicken in a single layer for 2 to 3 minutes per side until charred at the edges and cooked through, then set aside.","Throw the peppers and onion into the same pan and cook over high heat for 4 to 5 minutes, tossing occasionally, until softened with real char spots.","Return the chicken to the pan, squeeze over the rest of the lime, and toss everything together with the cilantro.","Pile the sizzling fajita mixture into the romaine cups and top each with slices of avocado."],"tip":"Resist the urge to stir constantly — char only happens when you leave things alone long enough to get slightly nervous."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_chicken_cauliflower_rice', '{"id":"greek_chicken_cauliflower_rice","name":"Greek Chicken over Lemon Cauliflower Rice","emoji":"🇬🇷","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"cauliflower","q":0.5},{"f":"feta","q":60},{"f":"olives","q":50},{"f":"cherry_tomatoes","q":200},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Toss the chicken thighs with half the olive oil, the oregano, half the lemon''s juice, a little minced garlic, salt, and pepper, and marinate for at least 10 minutes.","Sear the thighs in a hot skillet over medium-high for 5 to 6 minutes per side until burnished and cooked through, then rest them on a board.","Pulse the cauliflower into rice-sized bits, then sauté it in the same pan with the remaining oil and garlic for 4 to 5 minutes until tender and picking up the chicken''s browned bits.","Season the cauliflower rice with the rest of the lemon juice, salt, and pepper, and spread it over a platter.","Slice the chicken and arrange it on top with the halved cherry tomatoes, diced cucumber, olives, and crumbled feta.","Shower with chopped parsley and serve with lemon wedges on the side."],"tip":"Cauliflower rice cooked in the chicken pan tastes suspiciously like effort, and no one needs to know it took five minutes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheeseburger_cabbage_skillet', '{"id":"cheeseburger_cabbage_skillet","name":"Cheeseburger Cabbage Skillet","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"cabbage","q":0.5},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cheddar","q":80},{"f":"tomato","q":1},{"f":"olive_oil","q":15},{"f":"paprika","q":4},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in your largest skillet over medium-high and brown the ground beef hard for 5 to 6 minutes, breaking it up but letting it develop crusty bits before you stir.","Add the diced onion and cook 3 minutes until translucent, then stir in the garlic and paprika for 30 seconds until fragrant.","Pile in the thinly sliced cabbage — it will look absurd, then shrink — and cook, tossing every couple of minutes, for 8 to 10 minutes until wilted and sweet with golden edges.","Fold in the diced tomato, season assertively with salt and pepper, and cook 2 more minutes until the tomato slumps into the beef.","Scatter the cheddar over the top, cover, and let it melt into gooey pockets for about 2 minutes.","Serve straight from the skillet like the honest one-pan dinner it is."],"tip":"It tastes like a drive-thru cheeseburger that got a promotion — the pickle-craving is normal, lean into it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_shrimp_cauliflower_rice', '{"id":"lemon_shrimp_cauliflower_rice","name":"Lemon Garlic Shrimp with Buttery Cauliflower Rice","emoji":"🍤","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"cauliflower","q":0.5},{"f":"butter","q":30},{"f":"olive_oil","q":20},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"broth","q":60},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Pulse the cauliflower into rice-sized grains and pat the shrimp completely dry, seasoning them with salt and pepper.","Heat the olive oil in a large skillet over medium-high and sear the shrimp in a single layer for 90 seconds per side until pink and just curled into loose C-shapes, then transfer to a plate — a tight O-shape means overdone.","Melt the butter in the same pan, add the minced garlic, and cook 30 seconds until fragrant but not browned.","Stir in the cauliflower rice and broth and cook 4 to 5 minutes, stirring, until tender and the pan is nearly dry.","Return the shrimp with any juices, squeeze in the lemon, and toss for a final minute so everything glosses over.","Finish with chopped parsley, black pepper, and lemon wedges."],"tip":"Shrimp cook in the time it takes to find your tongs, so have everything else done before they hit the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_chicken_spinach_skillet', '{"id":"tuscan_chicken_spinach_skillet","name":"Tuscan Chicken and Spinach Skillet with Ricotta","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"spinach","q":150},{"f":"ricotta","q":150},{"f":"roasted_red_peppers","q":80},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"broth","q":100},{"f":"parmesan","q":20},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Halve the chicken breasts horizontally into cutlets, pat dry, and season with salt, pepper, and oregano.","Heat the olive oil in a large skillet over medium-high and sear the cutlets 4 minutes per side until golden and cooked through, then set them on a plate.","Lower the heat to medium, cook the garlic in the pan drippings for 30 seconds, then add the sliced roasted red peppers and broth, scraping up the fond.","Whisk in the ricotta and parmesan and simmer 2 to 3 minutes until the sauce is creamy and coats the back of a spoon.","Fold in the spinach a handful at a time until it wilts into the sauce, then nestle the chicken back in and spoon sauce over the top.","Simmer one more minute to reunite everything, taste for salt, and serve hot from the pan."],"tip":"Ricotta makes a gentler, lighter cream sauce than heavy cream — whisk it in off the boil so it stays silky instead of grainy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_stuffed_zucchini_boats', '{"id":"turkey_stuffed_zucchini_boats","name":"Italian Turkey Stuffed Zucchini Boats","emoji":"🥒","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"zucchini","q":3},{"f":"crushed_tomatoes","q":250},{"f":"mozzarella","q":80},{"f":"parmesan","q":20},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"oregano","q":3},{"f":"basil","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise, and scoop out the seedy centers with a spoon, leaving a 1 cm wall; chop the scooped flesh and reserve it.","Brush the boats with a little of the olive oil, season with salt, and roast cut-side up for 10 minutes to start them softening.","Meanwhile, brown the ground turkey in the remaining oil over medium-high for 5 to 6 minutes, then add the diced onion, reserved zucchini flesh, and garlic and cook 3 minutes more.","Stir in the crushed tomatoes, oregano, salt, and pepper and simmer 5 minutes until the filling is thick enough to hold its shape on a spoon.","Mound the filling into the boats, top with mozzarella and parmesan, and bake 15 minutes until the cheese is bubbling and spotted brown.","Rest for 5 minutes, then scatter with torn basil before serving."],"tip":"Scooping the seeds is not optional — a watery boat sinks even the best filling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_ginger_pork_green_beans', '{"id":"garlic_ginger_pork_green_beans","name":"Garlic-Ginger Pork with Snappy Green Beans","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","dairy-free","high-protein"],"allergens":["soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"green_beans","q":400},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":20},{"f":"scallions","q":0.5},{"f":"black_pepper","q":2}],"steps":["Slice the pork loin against the grain into thin strips and toss with half the soy sauce and a good grind of black pepper; let it sit 10 minutes while you trim the green beans.","Heat half the olive oil in a wok or large skillet until it just starts to smoke, then stir-fry the green beans for 4 to 5 minutes until blistered and wrinkled in spots; transfer to a plate.","Add the remaining olive oil and sear the pork in a single layer for 2 minutes without touching it, then stir-fry 2 minutes more until the edges brown.","Push the pork aside and sizzle the minced garlic and ginger in the center of the pan for 30 seconds until wildly fragrant.","Return the green beans, splash in the remaining soy sauce, and toss everything over high heat for a final minute until glossy.","Kill the heat, stir in the sesame oil, and top with sliced scallions."],"tip":"Sesame oil is a finishing perfume, not a cooking fat — add it off the heat or you will torch its charm."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_stuffed_avocados', '{"id":"caprese_stuffed_avocados","name":"Caprese Stuffed Avocados with Balsamic Drizzle","emoji":"🥑","cuisine":"Italian","meal":["lunch"],"diets":["vegetarian","low-carb","gluten-free"],"allergens":["dairy"],"time":15,"servings":2,"ing":[{"f":"avocado","q":2},{"f":"mozzarella","q":120},{"f":"cherry_tomatoes","q":200},{"f":"basil","q":0.5},{"f":"balsamic_vinegar","q":30},{"f":"olive_oil","q":20},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Simmer the balsamic vinegar in a small pan over medium heat for 3 to 4 minutes until it reduces by half and coats a spoon like thin syrup, then set aside to thicken as it cools.","Quarter the cherry tomatoes, dice the mozzarella into small cubes, and tear the basil leaves by hand.","Toss the tomatoes, mozzarella, and basil with the olive oil, salt, and a generous grind of black pepper.","Halve and pit the avocados, then scoop out a spoonful from each cavity to widen the bowl, dicing the scooped flesh into the salad.","Season the avocado halves with salt, pile the caprese mixture high into each one, and drizzle the balsamic reduction over the top.","Serve immediately, while the avocado is still bright green and smug about it."],"tip":"Reduce the balsamic while you chop — walk away and you will learn what burnt vinegar does to a kitchen''s morale."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_mushroom_chicken_thighs', '{"id":"creamy_mushroom_chicken_thighs","name":"Creamy Mushroom Chicken Thighs","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"mushrooms","q":300},{"f":"sour_cream","q":120},{"f":"broth","q":150},{"f":"butter","q":20},{"f":"olive_oil","q":15},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"paprika","q":4},{"f":"parsley","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pat the chicken thighs dry and season both sides with salt, pepper, and half the paprika.","Heat the olive oil in a deep skillet over medium-high and sear the thighs 5 to 6 minutes per side until deeply golden, then set them aside on a plate.","Melt the butter in the drippings, add the sliced mushrooms in a single layer, and resist stirring for 3 minutes so they brown properly before tossing; cook 3 minutes more with the diced onion until everything is bronzed.","Stir in the garlic and remaining paprika for 30 seconds, then pour in the broth and scrape up the browned bits, simmering 2 minutes to reduce slightly.","Drop the heat to low, whisk in the sour cream until the sauce is smooth and pale gold, and return the chicken with its juices to simmer gently for 5 minutes until the sauce coats a spoon.","Taste for salt, scatter with chopped parsley, and serve with plenty of sauce over each thigh."],"tip":"Sour cream splits if it boils, so once it goes in, keep the pan at a lazy murmur, not a rolling argument."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('denver_omelet_skillet', '{"id":"denver_omelet_skillet","name":"Denver Omelet Skillet","emoji":"🍳","cuisine":"American","meal":["breakfast"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"bacon","q":150},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"cheddar","q":80},{"f":"butter","q":15}],"steps":["Melt the butter in a 10-inch oven-safe skillet over medium heat until it foams, then add the diced ham, bell pepper, and onion.","Saute for 5 to 6 minutes, stirring occasionally, until the ham edges brown and the peppers soften and smell sweet.","Whisk the eggs with a pinch of salt and plenty of black pepper until no streaks of white remain, then pour them over the vegetables and lower the heat.","Let the eggs set undisturbed for 2 minutes, then drag a spatula around the edges so uncooked egg flows underneath.","Scatter the cheddar on top, cover, and cook 3 to 4 more minutes until the center barely jiggles and the cheese melts into glossy pools.","Cut into wedges straight from the skillet and serve hot."],"tip":"Dice the ham and peppers the same size so every bite gets the full Denver treatment instead of a pepper ambush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('fluffy_cottage_cheese_omelet', '{"id":"fluffy_cottage_cheese_omelet","name":"Fluffy Cottage Cheese Omelet","emoji":"🥚","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"cottage_cheese","q":200},{"f":"spinach","q":60},{"f":"butter","q":15}],"steps":["Whisk the eggs vigorously for a full minute with a pinch of salt until frothy and pale, which is the secret to a cloud-like texture.","Melt half the butter in a nonstick skillet over medium-low heat and pour in half the eggs, tilting the pan to coat.","When the edges set but the surface still looks glossy, about 2 minutes, spoon half the cottage cheese and a handful of spinach down the center.","Cover for 60 seconds so the spinach wilts and the cheese warms, then fold the omelet over itself and slide it onto a plate.","Repeat with the remaining butter, eggs, and filling, and finish both omelets with cracked black pepper."],"tip":"Keep the heat gentle; a browned omelet is a breakfast confession, not a badge of honor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_club_lettuce_wraps', '{"id":"turkey_club_lettuce_wraps","name":"Turkey Club Lettuce Wraps","emoji":"🥬","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":[],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":250},{"f":"bacon","q":100},{"f":"romaine","q":1},{"f":"tomato","q":2},{"f":"avocado","q":1}],"steps":["Cook the bacon in a cold skillet set over medium heat, turning occasionally, until deeply crisp, about 8 minutes, then drain on paper towels.","Separate the romaine into 8 sturdy outer leaves, rinse, and pat completely dry so the mayonnaise has something to cling to.","Slice the tomatoes thinly, season them with salt, and cut the avocado into ribbons.","Spread each leaf with a thin swipe of mayonnaise, then layer on turkey, tomato, avocado, and a shard of bacon.","Stack two leaves per wrap for structural integrity, fold like a taco, and secure with a toothpick if they get rowdy."],"tip":"Salt the tomato slices five minutes ahead so they taste like summer instead of wet cardboard."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avocado_egg_salad_wraps', '{"id":"avocado_egg_salad_wraps","name":"Avocado Egg Salad Wraps","emoji":"🥑","cuisine":"American","meal":["lunch"],"diets":["vegetarian","low-carb","gluten-free","dairy-free"],"allergens":["eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"avocado","q":1.5},{"f":"romaine","q":1},{"f":"lemon","q":0.5},{"f":"onion","q":0.3}],"steps":["Lower the eggs into boiling water and cook exactly 10 minutes, then plunge them into ice water for 5 minutes before peeling.","Mash the avocado in a bowl with the lemon juice, a generous pinch of salt, and black pepper until creamy but still a little chunky.","Chop the eggs roughly and mince the onion finely, then fold both into the avocado until everything is coated in green.","Taste and adjust with more lemon or salt; the mixture should be bright enough to make you blink.","Separate the romaine into crisp leaves and pile the egg salad into each one just before eating so the lettuce stays snappy."],"tip":"The lemon juice is doing double duty as seasoning and avocado bodyguard, so do not skimp on it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_yogurt_chicken_salad', '{"id":"greek_yogurt_chicken_salad","name":"Greek Yogurt Chicken Salad","emoji":"🥗","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"greek_yogurt","q":150},{"f":"celery","q":100},{"f":"onion","q":0.3},{"f":"lemon","q":0.5},{"f":"romaine","q":1}],"steps":["Poach the chicken breasts in barely simmering salted water for 12 to 15 minutes until they register 165F at the thickest point, then rest 5 minutes.","Shred the chicken into bite-size pieces while still warm; warm chicken drinks up dressing far better than cold.","Stir the greek yogurt with the lemon juice, salt, and pepper until smooth and tangy.","Fold in the chicken, finely diced celery, and minced onion until every shred is glossed with dressing.","Chill for 10 minutes if you can bear the wait, then spoon into crisp romaine leaves and serve."],"tip":"Keep the poaching water at a lazy shimmer, not a boil, unless you enjoy chicken with the texture of a stress ball."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('parmesan_zucchini_fritters', '{"id":"parmesan_zucchini_fritters","name":"Parmesan Zucchini Fritters","emoji":"🥒","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","low-carb","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"zucchini","q":2.5},{"f":"eggs","q":2},{"f":"parmesan","q":100},{"f":"garlic","q":0.2},{"f":"olive_oil","q":45}],"steps":["Grate the zucchini on the large holes of a box grater, toss with a teaspoon of salt, and let it sit in a colander for 15 minutes.","Squeeze the zucchini in a clean kitchen towel with real conviction until you have wrung out nearly half a cup of liquid.","Stir the dry zucchini with the eggs, grated parmesan, minced garlic, and plenty of black pepper; the parmesan and egg act as the only binder you need.","Heat the olive oil in a wide skillet over medium heat until it shimmers, then drop in heaping tablespoons of batter and flatten gently.","Fry 3 to 4 minutes per side until deeply golden and lacy at the edges, working in batches so the pan never crowds.","Drain on a rack, sprinkle with flaky salt, and eat while the cheese is still crackly."],"tip":"Every drop of water you fail to squeeze out returns later as a soggy fritter, so channel your grievances into that towel."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_lime_shrimp_salad', '{"id":"chili_lime_shrimp_salad","name":"Chili Lime Shrimp Salad","emoji":"🍤","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"romaine","q":1},{"f":"olive_oil","q":30},{"f":"cilantro","q":0.3}],"steps":["Pat the shrimp bone dry, then toss with half the olive oil, the zest of one lime, chili powder, and a big pinch of salt.","Sear the shrimp in a screaming-hot skillet for 90 seconds per side until they curl into loose commas and pick up charred edges; pull them off immediately.","Whisk the remaining olive oil with the juice of both limes, salt, and a pinch of chili to make a dressing that bites back.","Chop the romaine into ribbons, dice the avocado, and toss both with most of the dressing in a wide bowl.","Pile the warm shrimp on top, drizzle with the last of the dressing, and shower with torn cilantro."],"tip":"A shrimp curled into a tight O is overcooked; you want a relaxed C, like it is lounging in the dressing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_egg_bites', '{"id":"caprese_egg_bites","name":"Caprese Egg Bites","emoji":"🍅","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"mozzarella","q":120},{"f":"cherry_tomatoes","q":150},{"f":"basil","q":0.3},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 350F and brush eight muffin cups generously with the olive oil so the bites release cleanly.","Whisk the eggs with salt and pepper until completely uniform, then stir in most of the diced mozzarella and torn basil.","Halve the cherry tomatoes and drop two or three halves into each cup, cut side up, before pouring the egg mixture over them.","Top each cup with the reserved mozzarella and bake 18 to 20 minutes until puffed, set in the center, and blistered gold on top.","Cool 5 minutes in the pan; they will deflate slightly and release with a gentle twist.","Finish with fresh basil and a crack of pepper before serving warm."],"tip":"These reheat beautifully, so make a double batch unless you enjoy negotiating with future you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_stuffed_peppers', '{"id":"tuna_stuffed_peppers","name":"Mediterranean Tuna Stuffed Peppers","emoji":"🫑","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":20,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"bell_pepper","q":2},{"f":"feta","q":60},{"f":"olives","q":50},{"f":"olive_oil","q":25},{"f":"lemon","q":0.5},{"f":"onion","q":0.3}],"steps":["Drain the tuna thoroughly and flake it into a bowl with a fork until no large chunks remain.","Fold in the crumbled feta, chopped olives, minced onion, olive oil, lemon juice, and a heavy grind of black pepper.","Taste before salting; between the feta and olives, the mixture may already be seasoned like the Aegean.","Halve the bell peppers through the stem, scrape out the seeds and ribs, and season the cavities lightly.","Mound the tuna mixture into each pepper half, pressing gently so it holds, and finish with a final thread of olive oil and lemon."],"tip":"Choose peppers that sit flat on their backs, because a capsized pepper takes its filling down with it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_broccoli_cheddar_bake', '{"id":"chicken_broccoli_cheddar_bake","name":"Chicken Broccoli Cheddar Bake","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"broccoli","q":400},{"f":"cheddar","q":100},{"f":"sour_cream","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 400F and cut the chicken into bite-size chunks, seasoning them well with salt and pepper.","Sear the chicken in olive oil over medium-high heat for 3 to 4 minutes until golden on the outside but not fully cooked, then transfer to a baking dish.","Blanch the broccoli florets in boiling salted water for 2 minutes, drain hard, and scatter them among the chicken.","Stir the sour cream with the minced garlic and half the cheddar, then spoon it evenly over the dish like a duvet.","Top with the remaining cheddar and bake 18 to 20 minutes until the sauce bubbles at the edges and the top turns burnished gold.","Rest 5 minutes before serving so the sauce thickens from soupy to spoonable."],"tip":"Drain the broccoli like you mean it, because steamed florets hide a shocking amount of sauce-thinning water."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_salad_cucumber_boats', '{"id":"salmon_salad_cucumber_boats","name":"Salmon Salad Cucumber Boats","emoji":"🥒","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"cucumber","q":2},{"f":"greek_yogurt","q":100},{"f":"lemon","q":0.5},{"f":"onion","q":0.3}],"steps":["Season the salmon with salt and pepper and roast at 400F for 10 to 12 minutes until it flakes at the nudge of a fork, then cool slightly.","Flake the salmon into a bowl, discarding any skin, and keep the pieces chunky for texture.","Stir the greek yogurt with the lemon juice, chopped dill, minced onion, salt, and pepper, then fold in the salmon gently.","Halve the cucumbers lengthwise and drag a spoon down each center to scoop out the seeds, creating sturdy boats.","Salt the hollows lightly, pile in the salmon salad, and finish with extra dill and a squeeze of lemon."],"tip":"Scoop the cucumber seeds even if you are tempted to skip it, or your boats will spring a leak by lunchtime."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_mushroom_frittata', '{"id":"bacon_mushroom_frittata","name":"Bacon Mushroom Frittata","emoji":"🍄","cuisine":"American","meal":["breakfast","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"eggs","q":7},{"f":"bacon","q":120},{"f":"mushrooms","q":250},{"f":"parmesan","q":40},{"f":"onion","q":0.5}],"steps":["Heat the oven to 375F, then cook the chopped bacon in a 10-inch oven-safe skillet over medium heat until crisp, about 6 minutes.","Remove the bacon but leave 2 tablespoons of fat in the pan, then add the sliced mushrooms and onion.","Cook 8 minutes without fussing until the mushrooms release their liquid, the pan goes dry again, and everything turns deeply browned.","Whisk the eggs with the parmesan, salt, and pepper, stir the bacon back in, and pour the mixture over the vegetables.","Cook 2 minutes on the stovetop until the edges just set, then transfer to the oven for 10 to 12 minutes until the center is puffed and no longer wobbles.","Cool 5 minutes, run a spatula around the rim, and slide the frittata onto a board to slice into wedges."],"tip":"Mushrooms brown only after they stop steaming, so resist stirring and let the pan do its quiet work."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_ricotta_breakfast_bowls', '{"id":"berry_ricotta_breakfast_bowls","name":"Berry Ricotta Breakfast Bowls","emoji":"🫐","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","low-carb","gluten-free"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"ricotta","q":300},{"f":"berries","q":270},{"f":"almonds","q":30},{"f":"lemon","q":0.5}],"steps":["Whip the ricotta with the lemon zest and a tiny pinch of salt for a minute until it loosens into something silky and mousse-like.","Toast the almonds in a dry skillet over medium heat for 3 to 4 minutes, shaking often, until fragrant and golden at the edges.","Hull and quarter the strawberries and toss them with the blueberries and a small squeeze of lemon juice to wake up their sweetness.","Divide the whipped ricotta between two bowls, swooshing it up the sides with the back of a spoon.","Spoon the berries into the center and scatter the warm almonds over everything just before serving."],"tip":"That pinch of salt in the ricotta is not optional; it is the difference between dessert and breakfast that tastes like dessert."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_shawarma_style_plates', '{"id":"chicken_shawarma_style_plates","name":"Chicken Shawarma-Style Plates","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"greek_yogurt","q":150},{"f":"pita","q":2},{"f":"cucumber","q":0.8},{"f":"tomato","q":1.3},{"f":"onion","q":0.5},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Slice the chicken breast into thin strips and toss with half the olive oil, the juice of half the lemon, and a generous shower of cumin, smoked paprika, coriander, and salt until every piece is stained brick-red.","Let the chicken sit for 10 minutes while you dice the cucumber and tomato, slice the onion into thin half-moons, and stir the remaining lemon juice and a pinch of salt into the yogurt for a quick sauce.","Heat the remaining oil in a large skillet over medium-high until it shimmers, then lay the chicken in a single layer and leave it alone for 3 minutes so the edges char and crisp.","Flip and cook 3 to 4 minutes more, until the strips are deeply browned at the corners and no longer pink in the center.","Warm the pitas directly in the empty skillet for 30 seconds per side until soft and lightly blistered.","Pile the chicken over the pitas, scatter on the cucumber, tomato, and onion, and finish with thick ribbons of the lemony yogurt."],"tip":"Resist the urge to stir the chicken constantly — shawarma flavor lives in the char you only get by leaving it alone."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_beef_bean_chili', '{"id":"smoky_beef_bean_chili","name":"Smoky Beef and Bean Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":600},{"f":"black_beans","q":400},{"f":"tomato","q":3.3},{"f":"onion","q":1},{"f":"bell_pepper","q":1.3},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a heavy pot over medium-high, add the ground beef in one layer, and let it sear untouched for 4 minutes until a deep brown crust forms on the bottom before breaking it up.","Stir in the diced onion and bell pepper and cook 5 minutes, scraping the browned bits off the pot floor as the vegetables soften and turn glossy.","Add a heaping spoonful each of chili powder, smoked paprika, and cumin plus a pinch of salt, and toast the spices in the fat for a full minute until the whole kitchen smells like a barbecue pit.","Chop the tomatoes and add them with the drained black beans and a splash of water, then bring everything to a lively simmer.","Drop the heat to low, cover partially, and simmer 25 minutes, stirring occasionally, until the chili thickens enough that a spoon dragged across the bottom leaves a brief trail.","Taste, adjust the salt, and let it rest off the heat for 5 minutes so the flavors settle into each other."],"tip":"Chili is one of the few dishes that genuinely improves overnight, so make it a day early and take all the credit tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_burrito_skillet', '{"id":"turkey_burrito_skillet","name":"Turkey Burrito Skillet","emoji":"🌯","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"rice","q":120},{"f":"black_beans","q":150},{"f":"tomato","q":1.7},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.7},{"f":"cheddar","q":50},{"f":"olive_oil","q":10}],"steps":["Heat the oil in a deep skillet over medium-high and brown the ground turkey for 5 minutes, breaking it into rough crumbles and seasoning with chili powder, cumin, garlic powder, and salt.","Add the diced onion and bell pepper and cook 4 minutes more, until the onion turns translucent and the pepper edges begin to soften.","Stir in the rice, chopped tomatoes, drained black beans, and 350 ml of water, scraping any browned bits into the mix.","Bring to a boil, then cover, reduce the heat to low, and simmer 18 minutes without peeking, until the rice is tender and has drunk up nearly all the liquid.","Kill the heat, scatter the cheddar evenly over the top, and re-cover for 2 minutes so the cheese melts into molten pools.","Fluff gently at the table so everyone sees the cheese pull."],"tip":"All the burrito, none of the structural engineering — the skillet never falls apart in your hands."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_glazed_salmon_quinoa', '{"id":"maple_glazed_salmon_quinoa","name":"Maple-Glazed Salmon with Quinoa","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"quinoa","q":120},{"f":"maple_syrup","q":30},{"f":"broccoli","q":300},{"f":"olive_oil","q":15},{"f":"lemon","q":1}],"steps":["Rinse the quinoa, then simmer it in 300 ml of salted water, covered, for 15 minutes until the little spirals pop free and the water is absorbed.","Meanwhile, whisk the maple syrup with the juice of half the lemon, a pinch of salt, and plenty of black pepper to make a glaze that just coats a spoon.","Pat the salmon bone-dry, season it, and sear skin-side up in the hot oil over medium-high for 4 minutes until a golden crust releases easily from the pan.","Flip the fillets, tuck the broccoli florets around them with a splash of water, and pour the glaze over the fish.","Cook 3 to 4 minutes more, spooning the bubbling glaze over the salmon until it turns lacquered and the broccoli is bright green and crisp-tender.","Fluff the quinoa, top with the salmon and broccoli, and finish with the remaining lemon squeezed over everything."],"tip":"A dry salmon fillet is a browned salmon fillet — pat it down like you mean it before it touches the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_pepper_rice_skillet', '{"id":"beef_pepper_rice_skillet","name":"Beef and Pepper Rice Skillet","emoji":"🥩","cuisine":"Asian","meal":["lunch","dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"rice","q":130},{"f":"bell_pepper","q":2.1},{"f":"onion","q":0.7},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Simmer the rice in 280 ml of water, covered, for 15 minutes, then let it steam off the heat while you cook everything else.","Get a large skillet ripping hot over high heat, add the sesame oil, and sear the ground beef in a flat layer for 3 minutes until the underside is crusty and browned.","Break up the beef, push it to one side, and add the sliced bell peppers and onion, stir-frying 3 to 4 minutes until the peppers blister at the edges but keep their snap.","Pour in the soy sauce and a very generous grind of black pepper — this dish wants more pepper than feels reasonable — and toss everything together for 1 minute.","Add the cooked rice, pressing it into the pan so it sizzles and picks up the sauce, then fold it through the beef and vegetables.","Serve straight from the skillet while the bottom layer of rice is still crackling."],"tip":"Black pepper is the headline act here, not a garnish — grind until your wrist complains, then add a little more."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_lentil_stew', '{"id":"chicken_lentil_stew","name":"Mediterranean Chicken and Lentil Stew","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"chicken_thigh","q":600},{"f":"lentils_dry","q":250},{"f":"carrots","q":200},{"f":"onion","q":1},{"f":"tomato","q":2.5},{"f":"spinach","q":150},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Cut the chicken thighs into large chunks, season well with salt, oregano, and cumin, and brown them in the olive oil over medium-high heat for 5 minutes until golden on at least two sides.","Lift the chicken out, drop the heat to medium, and cook the diced onion and carrot in the same pot for 5 minutes, scraping up the browned chicken bits as the vegetables soften.","Add the chopped tomatoes and cook 3 minutes until they slump and turn jammy, then stir in the rinsed lentils and 1 liter of water.","Return the chicken and any juices to the pot, bring to a boil, then reduce to a gentle simmer and cook uncovered for 30 minutes, until the lentils are creamy-tender and the broth has thickened to a stew.","Fold in the spinach by the handful and let it wilt for 2 minutes.","Finish with the juice of the lemon and taste for salt — the acid is what makes the whole pot snap into focus."],"tip":"If the stew looks too thick, add water; if it looks too thin, wait ten minutes — lentils always get there eventually."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_fried_rice', '{"id":"pork_fried_rice","name":"Weeknight Pork Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","eggs","sesame"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"rice","q":140},{"f":"eggs","q":2},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Cook the rice in 300 ml of water for 15 minutes, then spread it on a plate to cool and dry out — slightly stale rice is the secret to fried rice that doesn''t clump.","Dice the pork tenderloin into small cubes and stir-fry it in the olive oil over high heat for 3 to 4 minutes until browned at the edges and just cooked through, then push it to the side of the pan.","Crack the eggs into the cleared space and scramble them hard for 30 seconds until just set in soft curds.","Add the diced carrot and frozen peas and toss for 2 minutes until the peas turn vivid green and the carrot loses its raw crunch.","Add the cooled rice, drizzle the soy sauce around the rim of the pan so it toasts on the hot metal, and toss everything for 2 minutes until each grain is coated and lightly crisped.","Kill the heat, stir in the sesame oil last so its fragrance survives, and serve immediately."],"tip":"Fried rice punishes patience — have every ingredient chopped and within arm''s reach before the pan gets hot."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_quinoa_paella_style', '{"id":"shrimp_quinoa_paella_style","name":"Shrimp Quinoa Paella-Style","emoji":"🥘","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"quinoa","q":150},{"f":"peas_frozen","q":100},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.7},{"f":"tomato","q":1.3},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Warm the olive oil in a wide, shallow skillet over medium heat and cook the diced onion and bell pepper for 5 minutes until soft and sweet.","Add the chopped tomato and a full teaspoon of smoked paprika and cook 3 minutes, stirring, until the mixture darkens into a thick, brick-colored sofrito.","Stir in the rinsed quinoa to coat it in the sofrito, pour in 350 ml of water with a good pinch of salt, and simmer uncovered for 12 minutes without stirring, paella-style.","Season the shrimp with salt and nestle them into the quinoa in a single layer along with the frozen peas.","Cover and cook 5 to 6 minutes, until the shrimp curl into loose pink commas and the quinoa at the pan''s edge crackles faintly — that''s your crust forming.","Rest off the heat for 3 minutes, then serve with lemon wedges and zero stirring, so the crispy bottom stays intact."],"tip":"That faint crackle near the end isn''t burning, it''s the socarrat-style crust — the best bite in the pan belongs to whoever scrapes it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_sweet_potato_skillet', '{"id":"turkey_sweet_potato_skillet","name":"Turkey and Sweet Potato Skillet","emoji":"🍠","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"sweet_potatoes","q":400},{"f":"bell_pepper","q":1.3},{"f":"onion","q":0.7},{"f":"spinach","q":150},{"f":"olive_oil","q":15}],"steps":["Dice the sweet potato into small 1 cm cubes — small is non-negotiable for even cooking — and sauté them in the olive oil over medium heat for 8 minutes, stirring now and then, until the edges caramelize.","Add a splash of water, cover for 3 minutes, and steam until a fork slides through a cube with no resistance.","Push the sweet potatoes aside, raise the heat to medium-high, and brown the ground turkey for 5 minutes, seasoning with smoked paprika, garlic powder, and salt as you break it up.","Add the diced onion and bell pepper and cook 4 minutes until softened and fragrant.","Fold in the spinach a handful at a time until it wilts into dark green ribbons, then toss everything together so the sweet potato stains the turkey golden.","Taste, hit it with black pepper and more salt if needed, and serve hot from the pan."],"tip":"This reheats so well it borders on suspicious — double it and breakfast, lunch, and dinner are all handled."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_patties_with_greens', '{"id":"salmon_patties_with_greens","name":"Golden Salmon Patties with Lemony Greens","emoji":"🐟","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein","gluten-free"],"allergens":["fish","eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"oats","q":50},{"f":"eggs","q":2},{"f":"greek_yogurt","q":100},{"f":"spinach","q":200},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Finely chop the salmon by hand until it holds together when squeezed, leaving a few larger pieces for texture.","Mix the salmon with the oats, eggs, the zest of the lemon, salt, and a pinch of black pepper, then let the mixture rest 5 minutes so the oats drink up moisture and bind everything.","Shape into four patties about 2 cm thick, pressing firmly so they hold their nerve in the pan.","Heat most of the olive oil in a skillet over medium and cook the patties 4 minutes per side, flipping only once, until deeply golden and crisp at the edges.","While they fry, stir half the lemon''s juice and a pinch of salt into the yogurt, and wilt the spinach in the remaining oil in a second pan for 2 minutes.","Plate the patties on the bed of greens with the lemon-yogurt sauce and the last lemon wedges alongside."],"tip":"Flip a patty only when it releases from the pan willingly — if it fights back, it needs another minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_ricotta_penne_bake', '{"id":"turkey_ricotta_penne_bake","name":"Turkey and Ricotta Penne Bake","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":300},{"f":"penne","q":120},{"f":"ricotta","q":150},{"f":"mozzarella","q":50},{"f":"parmesan","q":15},{"f":"tomato","q":2.5},{"f":"onion","q":0.7},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200 C and boil the penne in well-salted water for 2 minutes less than the package suggests — it finishes cooking in the oven and mushy pasta is a bake''s downfall.","Brown the ground turkey in the olive oil over medium-high for 5 minutes, then add the diced onion, oregano, and salt and cook 4 minutes more until soft.","Add the chopped tomatoes and simmer 8 minutes, crushing them with your spoon, until they collapse into a rough, clingy sauce.","Fold the drained penne into the sauce, then dollop the ricotta throughout in generous spoonfuls, swirling just once so pockets of cream stay intact.","Transfer to a baking dish, scatter the mozzarella and parmesan over the top, and bake 15 minutes until the cheese is bronzed and bubbling at the corners.","Rest 5 minutes before serving — molten ricotta shows no mercy."],"tip":"Swirl the ricotta once and walk away; overmixing turns luscious pockets into beige sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_medallions_with_apples', '{"id":"pork_medallions_with_apples","name":"Pork Medallions with Caramelized Apples","emoji":"🍎","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"apple","q":2},{"f":"onion","q":0.7},{"f":"butter","q":20},{"f":"maple_syrup","q":15},{"f":"olive_oil","q":10}],"steps":["Slice the pork tenderloin into 3 cm medallions, press each one gently flat with your palm, and season generously with salt, pepper, and a whisper of dried thyme.","Heat the olive oil in a skillet over medium-high until shimmering and sear the medallions 3 minutes per side, until golden-crusted and just blushing pink at the center, then rest them on a plate.","Drop the heat to medium, melt the butter in the same pan, and add the sliced apples and onion, scraping up the porky browned bits.","Cook 6 to 8 minutes, stirring occasionally, until the apples turn amber at the edges and the onion melts into softness.","Drizzle in the maple syrup and a splash of water, letting it bubble into a glossy pan sauce that coats the back of a spoon.","Return the medallions and their resting juices to the pan for a final minute, spooning the apples and sauce over the top."],"tip":"Those juices pooling under the resting pork are free sauce — tipping them back into the pan is the closest cooking gets to a refund."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_edamame_stirfry', '{"id":"chicken_edamame_stirfry","name":"Chicken and Edamame Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["high-protein","dairy-free","low-carb"],"allergens":["soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"edamame_frozen","q":200},{"f":"broccoli","q":250},{"f":"bell_pepper","q":1.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Slice the chicken breast into thin, even strips and pat them dry so they sear instead of steam.","Heat half the sesame oil in a wok or wide skillet over high heat until it just starts to smoke, then stir-fry the chicken for 4 minutes until golden at the edges and cooked through, and set it aside.","Add the remaining oil, then the broccoli florets and sliced bell pepper with a splash of water, tossing for 3 minutes until the broccoli turns emerald and the water hisses away.","Add the frozen edamame straight from the bag and stir-fry 2 minutes until heated through and glossy.","Return the chicken, pour the soy sauce down the hot side of the pan so it sizzles and reduces on contact, and toss for a final minute until everything is lacquered.","Finish with a crack of black pepper and serve immediately, while the vegetables still have their bite."],"tip":"A stir-fry is a sprint, not a marathon — if you can answer a text mid-cook, your pan isn''t hot enough."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_parmesan_skillet', '{"id":"eggplant_parmesan_skillet","name":"Eggplant Parmesan Skillet","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"olive_oil","q":30},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"mozzarella","q":100},{"f":"parmesan","q":30},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Slice the eggplant into 1-centimeter rounds, salt them generously, and let them sit 10 minutes before patting dry so they sear instead of steam.","Heat the olive oil in a large oven-safe skillet over medium-high and brown the eggplant in a single layer, about 3 minutes per side, until deeply golden at the edges.","Push the eggplant aside, soften the onion and garlic for 2 minutes, then pour in the crushed tomatoes with the oregano and simmer 8 minutes until the sauce thickens enough to mound on a spoon.","Nestle the eggplant into the sauce, scatter the mozzarella and parmesan over the top, and slide the skillet under a hot broiler for 3 to 4 minutes until the cheese blisters and bronzes.","Rest 5 minutes, shower with torn basil, and season with black pepper before serving straight from the pan."],"tip":"Salting the eggplant first is the difference between custardy slices and a sad oil sponge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_ziti_style_penne', '{"id":"baked_ziti_style_penne","name":"Baked Ziti-Style Penne","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["dairy","gluten"],"time":50,"servings":4,"ing":[{"f":"penne","q":320},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":600},{"f":"oregano","q":3},{"f":"ricotta","q":250},{"f":"mozzarella","q":150},{"f":"parmesan","q":40},{"f":"basil","q":0.3},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200C and boil the penne in well-salted water for 2 minutes less than the package says, so it finishes cooking in the sauce without going mushy.","Meanwhile, warm the olive oil in a wide pan over medium heat and cook the onion and garlic for 5 minutes until translucent and sweet-smelling.","Add the crushed tomatoes and oregano and simmer 10 minutes until the sauce darkens a shade and loses its raw-tomato tang.","Fold the drained pasta into the sauce with dollops of ricotta, leaving visible white streaks rather than stirring it smooth.","Transfer to a baking dish, top with the mozzarella and parmesan, and bake 15 to 18 minutes until the cheese is molten with golden spots at the edges.","Rest 10 minutes so the layers set, then finish with torn basil and plenty of black pepper."],"tip":"Undercooked pasta going into the oven is the whole trick — al dente in the pot means perfect in the dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('veggie_paella_style_rice', '{"id":"veggie_paella_style_rice","name":"Veggie Paella-Style Rice","emoji":"🥘","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","vegan","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"paprika","q":6},{"f":"turmeric","q":2},{"f":"rice","q":300},{"f":"broth","q":750},{"f":"artichoke_hearts","q":240},{"f":"peas_frozen","q":150},{"f":"olives","q":40},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in your widest skillet over medium heat and cook the onion and bell pepper for 6 minutes until soft and beginning to caramelize at the edges.","Stir in the garlic, grated tomato, paprika, and turmeric and cook 3 minutes until the mixture darkens into a thick, jammy sofrito.","Add the rice and stir for 1 minute to coat every grain, then pour in the hot broth with the salt and shake the pan level — no stirring from here on.","Simmer uncovered over medium-low for 15 minutes, then tuck in the artichoke hearts, peas, and olives and cook 5 minutes more until the liquid is absorbed.","Raise the heat to high for 60 to 90 seconds to coax out the socarrat, that crackly caramelized crust on the bottom — listen for the faint snap.","Rest off the heat under a clean towel for 5 minutes, then finish with lemon wedges, parsley, and black pepper."],"tip":"Resist stirring after the broth goes in — the crusty bottom layer is a feature, not a mistake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_stroganoff_pasta', '{"id":"mushroom_stroganoff_pasta","name":"Mushroom Stroganoff Pasta","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"penne","q":180},{"f":"butter","q":20},{"f":"olive_oil","q":15},{"f":"mushrooms","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"flour","q":10},{"f":"paprika","q":2},{"f":"broth","q":200},{"f":"sour_cream","q":120},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Boil the penne in salted water until just al dente, reserving a mugful of the starchy cooking water before you drain.","While the pasta cooks, melt the butter with the olive oil in a large skillet over high heat and sear the mushrooms undisturbed for 4 minutes until deeply browned before stirring — crowding and fiddling are the enemies of color.","Lower the heat to medium, add the onion and garlic, and cook 4 minutes until soft, then sprinkle in the flour and paprika and stir for 1 minute to cook off the raw taste.","Pour in the broth, scraping up the browned bits, and simmer 3 minutes until the sauce thickens enough to coat a spoon.","Pull the pan off the heat, stir in the sour cream until silky, then fold in the pasta with a splash of reserved water to loosen.","Season boldly with salt and black pepper and shower with chopped parsley."],"tip":"Add the sour cream off the heat or it will curdle into cottage-cheese confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanakorizo_greek_spinach_rice', '{"id":"spanakorizo_greek_spinach_rice","name":"Spanakorizo (Greek Spinach Rice)","emoji":"🥬","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"olive_oil","q":40},{"f":"onion","q":1},{"f":"scallions","q":0.5},{"f":"garlic","q":0.3},{"f":"rice","q":180},{"f":"broth","q":450},{"f":"spinach","q":200},{"f":"lemon","q":1},{"f":"feta","q":80},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a deep pot over medium heat and cook the onion, scallions, and garlic for 5 minutes until soft and fragrant but not browned.","Stir in the rice and toast for 2 minutes until the grains turn faintly translucent at the edges.","Pour in the broth, season with salt, and simmer covered on low for 12 minutes until the rice is nearly tender.","Pile the spinach on top in big handfuls, cover again, and let it steam down for 3 minutes before folding it through — it will look like too much until it isn''t.","Off the heat, stir in the juice of the whole lemon and half its zest, then rest covered for 5 minutes so the rice drinks up the last of the liquid.","Serve warm rather than hot, crowned with crumbled feta, parsley, and a crack of black pepper."],"tip":"Greeks eat this closer to room temperature, when the lemon and olive oil actually taste like themselves."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('huevos_rancheros_black_beans', '{"id":"huevos_rancheros_black_beans","name":"Huevos Rancheros with Black Beans","emoji":"🍳","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free","high-protein"],"allergens":["eggs","gluten"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"olive_oil","q":15},{"f":"black_beans","q":200},{"f":"cumin","q":2},{"f":"salsa","q":200},{"f":"eggs","q":4},{"f":"avocado","q":1},{"f":"lime","q":0.5},{"f":"cilantro","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Warm the black beans in a small saucepan with the cumin, a pinch of salt, and a splash of water, mashing a few against the side until the mixture is creamy but still chunky.","Toast the tortillas one at a time in a dry skillet over medium-high heat, about 45 seconds per side, until speckled and pliable, then keep them warm under a towel.","Simmer the salsa in the same skillet for 2 minutes until it thickens slightly and smells sweet.","Push the salsa to the edges, add the olive oil to the center, and crack in the eggs; fry 3 minutes until the whites are set but the yolks still shimmer.","Layer each plate with tortillas, beans, an egg, and a generous spoonful of the warm salsa.","Finish with sliced avocado, a squeeze of lime, cilantro, and black pepper, and serve before the yolks lose their nerve."],"tip":"Frying the eggs directly in the simmering salsa saves a pan and lets the whites soak up the sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_korma_style_curry', '{"id":"vegetable_korma_style_curry","name":"Vegetable Korma-Style Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","vegan","dairy-free","gluten-free"],"allergens":["nuts"],"time":50,"servings":4,"ing":[{"f":"cashews","q":80},{"f":"coconut_milk","q":250},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"curry_powder","q":8},{"f":"garam_masala","q":4},{"f":"turmeric","q":2},{"f":"potatoes","q":300},{"f":"carrots","q":200},{"f":"cauliflower","q":0.5},{"f":"broth","q":300},{"f":"peas_frozen","q":150},{"f":"rice","q":250},{"f":"cilantro","q":0.3},{"f":"salt","q":6}],"steps":["Soak the cashews in boiling water for 15 minutes, then blend them with the coconut milk until completely smooth — this is your korma cream, so blend past the gritty stage.","Start the rice in a separate pot while the cashews soak, and cut the potatoes, carrots, and cauliflower into even bite-size pieces.","Heat the oil in a heavy pot over medium and cook the onion for 8 minutes until golden, then add the garlic, ginger, curry powder, garam masala, and turmeric and fry 1 minute until the spices smell toasty rather than raw.","Add the potatoes, carrots, cauliflower, broth, and salt, cover, and simmer 15 minutes until a knife slides easily into the potato.","Pour in the cashew-coconut cream and the peas and simmer gently, uncovered, for 5 minutes until the sauce is thick enough to cling to the vegetables.","Taste for salt, spoon over the rice, and finish with a flurry of cilantro."],"tip":"If the sauce breaks or looks thin, blend a ladleful and stir it back in — instant body, no cream required."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ratatouille_baked_eggs', '{"id":"ratatouille_baked_eggs","name":"Ratatouille Baked Eggs","emoji":"🍅","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","dairy-free","low-carb"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"olive_oil","q":30},{"f":"eggplant","q":0.5},{"f":"zucchini","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"eggs","q":4},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Dice the eggplant, zucchini, bell pepper, and onion into even 2-centimeter pieces so they cook at the same pace.","Heat the olive oil in a large oven-safe skillet over medium-high and cook the vegetables with a good pinch of salt for 10 minutes, stirring occasionally, until browned in spots and starting to slump.","Add the garlic and oregano for the final minute, then pour in the crushed tomatoes and simmer 10 minutes until the stew is thick enough to hold a spoon trail.","Press four wells into the ratatouille with the back of a spoon and crack an egg into each one.","Cover and cook over low heat for 6 to 8 minutes, until the whites are just set and the yolks still wobble when you nudge the pan.","Season with black pepper, scatter with torn basil, and bring the skillet straight to the table."],"tip":"The eggs keep cooking in the hot vegetables, so pull the pan when they look slightly underdone."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_grilled_cheese', '{"id":"caprese_grilled_cheese","name":"Caprese Grilled Cheese","emoji":"🥪","cuisine":"Italian","meal":["lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"mozzarella","q":150},{"f":"tomato","q":1},{"f":"basil","q":0.3},{"f":"butter","q":20},{"f":"balsamic_vinegar","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Slice the tomato thinly, salt the slices, and let them drain on a paper towel for 5 minutes so they don''t flood the sandwich.","Layer the mozzarella, blotted tomato, and basil leaves between the bread slices, seasoning the tomato layer with black pepper and a few drops of balsamic vinegar.","Butter the outside of each sandwich edge to edge — the crust corners are where regret lives.","Cook in a skillet over medium-low heat for 4 to 5 minutes per side, pressing gently with a spatula, until the bread is deep golden and the cheese sags when you lift a corner.","Rest 2 minutes before slicing on the diagonal so the molten mozzarella doesn''t make a break for it."],"tip":"Medium-low heat is non-negotiable — hot pans give you burnt bread hugging cold cheese."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_quesadillas', '{"id":"sweet_potato_black_bean_quesadillas","name":"Sweet Potato Black Bean Quesadillas","emoji":"🍠","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"sweet_potatoes","q":350},{"f":"black_beans","q":150},{"f":"cumin","q":3},{"f":"chili_powder","q":3},{"f":"lime","q":0.5},{"f":"scallions","q":0.3},{"f":"tortillas","q":4},{"f":"cheddar","q":80},{"f":"olive_oil","q":15},{"f":"salsa","q":100},{"f":"salt","q":3}],"steps":["Peel and dice the sweet potatoes, then steam or microwave them with a splash of water for 6 to 8 minutes until fork-tender.","Mash them roughly with the black beans, cumin, chili powder, lime juice, sliced scallions, and salt — aim for chunky, not baby food.","Spread the filling over half of each tortilla, top with grated cheddar, and fold into half-moons, pressing to seal.","Brush a skillet with olive oil and cook the quesadillas over medium heat for 3 minutes per side, until shatteringly crisp and stamped with golden-brown patches.","Rest 2 minutes so the filling sets, then slice into wedges and serve with salsa for dunking."],"tip":"The mash glues the quesadilla shut, so no more cheese avalanches when you flip."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_tomato_ricotta_soup', '{"id":"creamy_tomato_ricotta_soup","name":"Creamy Tomato Ricotta Soup","emoji":"🥣","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":600},{"f":"broth","q":400},{"f":"sugar","q":5},{"f":"oregano","q":2},{"f":"ricotta","q":150},{"f":"parmesan","q":20},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a soup pot over medium heat and cook the onion for 6 minutes until soft and sweet, adding the garlic for the last minute.","Pour in the crushed tomatoes, broth, sugar, oregano, and salt and simmer uncovered for 15 minutes, until the soup deepens from bright red to brick.","Blend until completely smooth with an immersion blender, then stir in two-thirds of the ricotta over low heat until the soup turns pale coral and velvety.","Taste and correct — a little more salt sharpens the tomato, a pinch more sugar rounds off any tinny edge.","Ladle into bowls and finish each with a dollop of the remaining ricotta, grated parmesan, torn basil, and a swirl of black pepper."],"tip":"That pinch of sugar isn''t cheating — it''s doing the job an August tomato would have done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_veggie_fried_quinoa', '{"id":"loaded_veggie_fried_quinoa","name":"Loaded Veggie Fried Quinoa","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","soy","sesame","gluten"],"time":30,"servings":2,"ing":[{"f":"quinoa","q":180},{"f":"olive_oil","q":15},{"f":"eggs","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"carrots","q":100},{"f":"broccoli","q":150},{"f":"peas_frozen","q":100},{"f":"corn_frozen","q":100},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"scallions","q":0.5},{"f":"black_pepper","q":1}],"steps":["Cook the quinoa in plenty of water for 12 minutes, drain well, and spread it on a tray to dry and cool — wet quinoa fries into porridge, so day-old is even better.","Heat half the olive oil in your largest skillet over high heat, scramble the eggs hard for 30 seconds until just set, and scrape them out onto a plate.","Add the remaining oil and stir-fry the garlic, ginger, diced carrots, and broccoli for 3 to 4 minutes until the broccoli turns vivid green with charred edges.","Add the quinoa, peas, and corn and press everything flat against the hot pan; let it sizzle undisturbed for 90 seconds so the quinoa crisps and pops.","Return the eggs, pour the soy sauce and sesame oil around the rim of the pan, and toss for a final minute until every grain is glossy.","Serve immediately, topped with sliced scallions and black pepper."],"tip":"Pressing the quinoa into the pan and leaving it alone is what buys you those crispy toasted bits."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_red_pepper_penne', '{"id":"roasted_red_pepper_penne","name":"Roasted Red Pepper Penne","emoji":"🌶️","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"penne","q":180},{"f":"olive_oil","q":30},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"roasted_red_peppers","q":250},{"f":"ricotta","q":60},{"f":"parmesan","q":40},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Boil the penne in aggressively salted water until al dente, saving a cup of pasta water before draining.","While it cooks, warm the olive oil in a skillet over medium heat and soften the onion and garlic for 4 minutes without letting them brown.","Blend the drained roasted red peppers with the onion mixture and the ricotta until completely smooth and the color of a Tuscan sunset.","Return the sauce to the skillet, simmer 3 minutes until it thickens slightly, and season with salt and black pepper.","Toss in the pasta with half the parmesan and enough reserved pasta water to make the sauce cling glossily to every tube.","Plate and finish with the remaining parmesan and torn basil."],"tip":"Jarred peppers did the roasting for you — spend the saved 40 minutes blending the sauce truly smooth."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_butter_chicken_with_olives', '{"id":"lemon_butter_chicken_with_olives","name":"Lemon butter chicken with olives","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","low-carb"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"flour","q":20},{"f":"butter","q":30},{"f":"olive_oil","q":15},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"broth","q":150},{"f":"olives","q":50},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Slice the chicken breasts horizontally into thin cutlets, season with salt and pepper, and dust both sides lightly with flour, shaking off the excess.","Heat the olive oil with half the butter in a wide skillet over medium-high until the foam subsides, then lay in the cutlets and cook 3 minutes per side until deeply golden; transfer to a plate.","Drop the heat to medium, add the minced garlic, and stir 30 seconds until fragrant but not browned.","Pour in the broth and the juice of the lemon, scraping up the browned bits, and simmer 2–3 minutes until the sauce reduces by half and just coats a spoon.","Swirl in the remaining butter and the halved olives, slide the chicken back in with any juices, and warm through for 1 minute.","Shower with chopped parsley and serve straight from the pan while the sauce is glossy."],"tip":"Thin cutlets cook fast — if you walk away to check your phone, you will own two chicken-flavored hockey pucks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_wedding_style_soup', '{"id":"italian_wedding_style_soup","name":"Italian wedding-style soup with turkey meatballs","emoji":"🍲","cuisine":"Italian","meal":["lunch","dinner"],"diets":["gluten-free","high-protein"],"allergens":["eggs","dairy"],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":500},{"f":"eggs","q":1},{"f":"parmesan","q":40},{"f":"rice","q":150},{"f":"broth","q":1500},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"spinach","q":150},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Mix the turkey with the egg, half the parmesan, a pinch of oregano, salt, and pepper, then roll into small meatballs about the size of a walnut and chill while you start the pot.","Warm the olive oil in a soup pot over medium heat and sweat the diced onion, carrots, and celery for 6–7 minutes until softened and sweet; stir in the minced garlic for 30 seconds.","Pour in the broth, bring it to a lively simmer, and stir in the rice.","Gently lower in the meatballs one at a time and simmer, uncovered, for 15–18 minutes until the rice is tender and the meatballs are cooked through.","Wilt in the spinach for the final 2 minutes, then taste and adjust the salt and pepper.","Ladle into bowls and finish each with the remaining parmesan."],"tip":"Wet your hands before rolling the meatballs and the mixture will stop treating your palms like flypaper."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_butter_salmon', '{"id":"tuscan_butter_salmon","name":"Tuscan butter salmon","emoji":"🐟","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"butter","q":25},{"f":"garlic","q":0.3},{"f":"cherry_tomatoes","q":200},{"f":"spinach","q":100},{"f":"milk","q":120},{"f":"parmesan","q":30},{"f":"olive_oil","q":10},{"f":"basil","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Pat the salmon fillets very dry, season with salt and pepper, and heat the olive oil in a skillet over medium-high until shimmering.","Sear the salmon skin-side up for 4 minutes until a golden crust releases easily from the pan, flip, cook 2 minutes more, and set aside on a plate.","Lower the heat to medium, melt the butter, and cook the minced garlic and halved cherry tomatoes for 3–4 minutes until the tomatoes blister and slump.","Pour in the milk, scatter in the parmesan, and simmer 2 minutes, stirring, until the sauce turns creamy and lightly thickened.","Fold in the spinach until just wilted, then nestle the salmon back in and spoon sauce over the top for a final minute of gentle heat.","Tear the basil over everything and serve straight from the skillet."],"tip":"A dry fillet and a hot pan are the whole secret — damp salmon steams, and steamed salmon sulks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_lemon_chicken_potatoes', '{"id":"greek_lemon_chicken_potatoes","name":"Greek lemon chicken and potatoes","emoji":"🍗","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":60,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"potatoes","q":450},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"oregano","q":4},{"f":"broth","q":120},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 220°C and cut the potatoes into thick wedges so they can roast without collapsing.","Whisk the olive oil with the juice of the lemon, minced garlic, oregano, salt, and a generous grind of pepper, then toss the chicken thighs and potatoes in it until every surface is slicked.","Arrange everything in a single layer in a roasting pan, chicken skin-side up, and pour the broth into the corners so the potatoes braise from below while they brown on top.","Roast for 40–45 minutes until the chicken is burnished and the potato edges are golden and crisp.","Spoon the lemony pan juices over everything and rest 5 minutes before serving.","Finish with a last squeeze from the spent lemon halves if you like it bracing."],"tip":"Crowd the pan and everything steams — give the potatoes elbow room and they will reward you with crispy corners."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pasta_primavera', '{"id":"pasta_primavera","name":"Pasta primavera","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"penne","q":180},{"f":"zucchini","q":1},{"f":"asparagus","q":150},{"f":"bell_pepper","q":1},{"f":"peas_frozen","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"parmesan","q":40},{"f":"lemon","q":0.5},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Boil the penne in well-salted water until just shy of al dente, then scoop out a cup of the starchy cooking water before draining.","Meanwhile, heat the olive oil in a large skillet over medium-high and sauté the sliced zucchini, asparagus pieces, and bell pepper strips for 5–6 minutes until crisp-tender with browned edges.","Add the minced garlic and frozen peas and cook 1 minute more until the garlic is fragrant and the peas are bright.","Tip in the drained pasta with a good splash of the reserved water and toss over the heat until the liquid turns silky and clings to the noodles.","Off the heat, stir in the parmesan, the juice of the half lemon, and torn basil, loosening with more pasta water if it tightens up.","Season boldly with black pepper and serve in warm bowls."],"tip":"That cup of pasta water is free sauce — pour it down the drain and you will be chasing dry noodles around the pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cacio_e_pepe', '{"id":"cacio_e_pepe","name":"Cacio e pepe","emoji":"🧀","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"spaghetti","q":200},{"f":"parmesan","q":80},{"f":"black_pepper","q":4},{"f":"salt","q":4}],"steps":["Toast the coarsely ground black pepper in a dry, wide skillet over medium heat for about 1 minute until it smells sharp and woodsy, then take the pan off the heat.","Boil the spaghetti in lightly salted water — less salty than usual, since the cheese carries plenty — until 1 minute shy of al dente, reserving a full cup of the cooking water.","Finely grate the parmesan into a bowl and whisk in a few spoonfuls of the hot pasta water until it forms a thick, smooth paste with no clumps.","Transfer the drained pasta to the pepper skillet with a splash of pasta water and toss over low heat for 30 seconds so every strand is coated.","Pull the pan off the heat, wait 15 seconds so the cheese will not seize, then add the parmesan paste and toss relentlessly until a glossy sauce hugs the noodles.","Loosen with extra pasta water a spoonful at a time and serve immediately in warm bowls."],"tip":"Cheese added over direct heat turns to chewing gum — patience off the flame is the entire recipe."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('panzanella_style_bread_salad', '{"id":"panzanella_style_bread_salad","name":"Panzanella-style bread salad","emoji":"🥖","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"bread","q":6},{"f":"tomato","q":4},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"chickpeas","q":150},{"f":"olives","q":50},{"f":"olive_oil","q":40},{"f":"balsamic_vinegar","q":20},{"f":"basil","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 200°C, tear the bread into rough bite-size chunks, toss with a third of the olive oil, and toast on a tray for 10–12 minutes until golden and audibly crunchy.","Cut the tomatoes into chunky wedges over a large bowl so every drop of juice lands in the salad, then season them with salt and let them sit 5 minutes to weep.","Add the chopped cucumber, thinly sliced onion, drained chickpeas, and halved olives to the bowl.","Whisk the remaining olive oil with the balsamic vinegar and pour it over everything.","Fold in the toasted bread and torn basil and let the salad rest 10 minutes so the croutons drink up the tomato juices without going soggy.","Taste, add pepper and more salt if needed, and serve at room temperature."],"tip":"Stale bread is not a compromise here, it is the job requirement — fresh fluffy bread dissolves into regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_gyro_style_pitas', '{"id":"chicken_gyro_style_pitas","name":"Chicken gyro-style pitas with yogurt sauce","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"greek_yogurt","q":150},{"f":"pita","q":2},{"f":"cucumber","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"garlic","q":0.2},{"f":"lemon","q":0.5},{"f":"olive_oil","q":15},{"f":"oregano","q":3},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Slice the chicken thighs into thin strips and toss with the olive oil, oregano, paprika, half the minced garlic, salt, pepper, and a squeeze of the lemon; marinate 10 minutes while you make the sauce.","Grate the cucumber, squeeze it dry in your fist over the sink, and stir it into the yogurt with the remaining garlic, the rest of the lemon juice, and a pinch of salt.","Sear the chicken in a screaming-hot skillet in a single layer, undisturbed for 3 minutes until charred at the edges, then toss and cook 3–4 minutes more until cooked through.","Warm the pitas in the emptied pan for 30 seconds per side until soft and pliable.","Pile each pita with chicken, sliced tomato, and slivered onion, then spoon the yogurt sauce generously over the top.","Fold, wrap the bottom in paper if you value your sleeves, and eat immediately."],"tip":"Squeezing the cucumber feels fussy until the day you skip it and your sauce becomes soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_pepper_walnut_dip_plate', '{"id":"roasted_pepper_walnut_dip_plate","name":"Roasted pepper and walnut dip plate","emoji":"🌶️","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts","gluten"],"time":25,"servings":2,"ing":[{"f":"roasted_red_peppers","q":200},{"f":"walnuts","q":80},{"f":"bread","q":1},{"f":"pita","q":2},{"f":"garlic","q":0.1},{"f":"olive_oil","q":25},{"f":"balsamic_vinegar","q":10},{"f":"cumin","q":2},{"f":"lemon","q":0.5},{"f":"cucumber","q":1},{"f":"salt","q":3},{"f":"paprika","q":2}],"steps":["Toast the walnuts in a dry skillet over medium heat for 3–4 minutes, shaking often, until they smell rich and nutty — pull them the moment they darken.","Tear the slice of bread into pieces and blitz it in a food processor with the walnuts until finely ground.","Add the drained roasted red peppers, garlic, balsamic vinegar, cumin, paprika, the juice of the half lemon, and a pinch of salt, then process to a thick, rustic paste, streaming in most of the olive oil as it runs.","Taste and adjust — it should be smoky, tangy, and just a little sweet from the peppers.","Warm the pitas in the skillet until soft, cut them into wedges, and slice the cucumber into spears.","Swoosh the dip across a plate, crater the center with the back of a spoon, drizzle with the last of the oil, and surround with pita and cucumber."],"tip":"The dip thickens and deepens overnight, so making it a day ahead is less a tip than an unfair advantage."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_asparagus_rice_risotto_style', '{"id":"lemon_asparagus_rice_risotto_style","name":"Lemon asparagus risotto-style rice","emoji":"🍚","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"rice","q":180},{"f":"asparagus","q":250},{"f":"broth","q":750},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"butter","q":20},{"f":"parmesan","q":50},{"f":"lemon","q":1},{"f":"olive_oil","q":10},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Keep the broth barely simmering in a small pot — cold broth added to hot rice stops the creamy magic every time.","Warm the olive oil with half the butter in a wide pan over medium heat and cook the finely diced onion 4 minutes until translucent, then stir in the garlic and the rice, toasting the grains 2 minutes until the edges look glassy.","Add the hot broth a ladleful at a time, stirring often and waiting until each addition is nearly absorbed before the next, about 20 minutes total.","When the rice is tender with the faintest chew at the center, stir in the asparagus pieces and cook 3–4 minutes until bright green and crisp-tender.","Off the heat, beat in the remaining butter, the parmesan, the zest-free juice of the lemon, salt, and plenty of pepper until the rice ripples loosely when you shake the pan.","Serve immediately in shallow bowls — it waits for no one."],"tip":"Risotto should slump lazily across the plate; if it stands at attention, loosen it with one more splash of broth."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sicilian_tuna_olive_pasta', '{"id":"sicilian_tuna_olive_pasta","name":"Sicilian tuna and olive pasta","emoji":"🫒","cuisine":"Italian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","fish"],"time":25,"servings":2,"ing":[{"f":"penne","q":180},{"f":"tuna_canned","q":160},{"f":"olives","q":60},{"f":"crushed_tomatoes","q":250},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Set the penne boiling in well-salted water and cook until just al dente, saving a half cup of the pasta water before draining.","While it cooks, warm the olive oil in a deep skillet over medium heat and sizzle the sliced garlic for about 1 minute until pale gold and fragrant — no darker.","Add the crushed tomatoes, oregano, and halved olives and simmer 8 minutes until the sauce thickens enough to hold a trail behind the spoon.","Fold in the drained tuna in big flakes and warm it gently for 2 minutes without stirring it to shreds.","Toss the pasta through the sauce with a splash of the reserved water until every tube is coated and glistening.","Finish with the juice of the half lemon, chopped parsley, and a heavy grind of black pepper."],"tip":"Treat the tuna like it is fragile and expensive; stir like a maniac and you will make tuna-flavored tomato paste."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_feta_olive_frittata', '{"id":"greek_feta_olive_frittata","name":"Greek feta and olive frittata","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"feta","q":100},{"f":"olives","q":50},{"f":"cherry_tomatoes","q":150},{"f":"spinach","q":100},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 190°C and whisk the eggs with the oregano, a small pinch of salt (the feta and olives bring plenty), and a good grind of pepper.","Warm the olive oil in an ovenproof skillet over medium heat and soften the sliced onion for 4 minutes, then add the halved cherry tomatoes and cook 2 minutes until they just begin to slump.","Pile in the spinach and stir until it collapses to a glossy tangle, about 1 minute.","Pour the eggs over the vegetables, scatter with the crumbled feta and halved olives, and cook undisturbed for 2 minutes until the edges set.","Slide the skillet into the oven and bake 8–10 minutes until the center is puffed and barely jiggles when you nudge the pan.","Rest 3 minutes, then cut into wedges straight from the skillet."],"tip":"Pull it while the middle still wobbles slightly — carryover heat finishes the job, and an overbaked frittata bounces."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
